function carryPhaseScore(c,phase,index=0){if(!c)return 0;const tags=unique([...(c.capabilities||[]),...(c.skillTags||[]),c.combat?.primary,c.combat?.macro,c.damage?.profile,c.classification?.primary]).map(slug),has=(...names)=>names.some(name=>tags.includes(slug(name))||tags.some(tag=>tag.includes(slug(name)))),ratings=c.ratings||{};let score=rolePhaseWeight(c,index,phase)+phaseValue(c.power?.[phase])*2+(Number(ratings.damage)||0)*1.1+(Number(ratings.tower)||0)*.35;if(c.profiles?.carry)score+=2.2;if(c.profiles?.hyperCarry)score+=phase==='late'?3.4:1.2;if(phase==='early')score+=has('Dive','Burst','Poke','Strong Ult','Lane Bully')?1.6:0;if(phase==='mid')score+=has('TeamFight','Strong Ult','Pick','Catch','AoE')?1.8:0;if(phase==='late')score+=has('DPS','Scaling','On-Hit','Range')?2.2:0;if(c.classification?.primary==='Marksman')score+=phase==='late'?1.8:1;if(c.combat?.macro==='Split')score+=phase==='mid'?1.1:phase==='late'?.7:.2;return score}
