function radarPoint(value,index,total,scale=5){const angle=(-90+index*360/total)*Math.PI/180,r=13+Math.max(0,Math.min(scale,Number(value)||0))/scale*42;return `${(60+Math.cos(angle)*r).toFixed(1)},${(60+Math.sin(angle)*r).toFixed(1)}`}
