function slotDifficulty(c){const raw=Math.max(0,Math.min(3,Number(c.difficulty)||0)),percent=Math.round(raw/3*100),label=raw>=2.4?'Hard':raw>=1.4?'Medium':raw>0?'Easy':'Unknown';return `<span class="slot-difficulty" aria-label="${esc(c.name)} difficulty ${raw.toFixed(1)} out of 3"><span>${filterIcon('className','Specialist')}<small>Difficulty</small><b>${esc(label)}</b></span><i><em style="width:${percent}%"></em></i><strong>${raw?raw.toFixed(1):'—'}<small>/3</small></strong></span>`}
