slotInsight=function(c,role){if(!c)return'';const power=c.power||{},skills=fullSkillRecords(c),tags=unique([...(c.roles||[]),...(c.combat?.positioning||[]),c.combat?.primary,c.combat?.secondary,c.combat?.macro,c.classification?.primary,c.classification?.secondary,c.damage?.type,c.damage?.profile,c.range,...(c.capabilities||[])]).filter(Boolean);return `<span class="slot-insight full" role="tooltip"><span class="slot-insight-head">${portrait(c,'lg')}<span><small>${esc(role||c.primaryRole||'Champion')} · ${esc((c.roles||[]).join(' / ')||'—')}</small><strong>${esc(c.name)}</strong><em>${esc([c.classification?.primary,c.classification?.secondary,c.damage?.type,c.damage?.profile].filter(Boolean).join(' · ')||'—')}</em></span></span><span class="slot-tags full">${tags.map(tag=>pill(tag,semanticTone(tag))).join('')}</span><span class="slot-phase"><span><small>Early</small><b>${esc(power.early||'—')}</b></span><span><small>Mid</small><b>${esc(power.mid||'—')}</b></span><span><small>Late</small><b>${esc(power.late||'—')}</b></span></span><span class="slot-full-meta"><span><small>Patch</small><b>${esc(c.metadata?.patch||'—')}</b></span><span><small>Tier</small><b>${esc(c.tier||'—')}</b></span><span><small>Range</small><b>${esc(c.range||'—')}</b></span><span><small>Skill records</small><b>${skills.length}</b></span></span>${championStatRadar(c)}${slotDifficulty(c)}${hoverKitSummary(c)}<span class="slot-skill-grid full">${skills.map(fullSkillTile).join('')}</span><small class="slot-hint">Click để chọn/đổi tướng · Hover skill để xem chi tiết đầy đủ</small></span>`}
