function phaseMicro(c){return `<div class="phase-micro" aria-label="Laning power"><span class="${slug(c.power.early)}"><small>E</small><b>${esc(c.power.early)}</b></span><span class="${slug(c.power.mid)}"><small>M</small><b>${esc(c.power.mid)}</b></span><span class="${slug(c.power.late)}"><small>L</small><b>${esc(c.power.late)}</b></span></div>`}
const TEAM_SKILL_TAG_REPAIRS={
  'Bonus DamageHeal':['Bonus Damage','Heal'],
  'Bonus DamageSpeed':['Bonus Damage','Speed'],
  'Burst DamageSlow AoE':['Burst Damage','Slow','AoE'],
  'ExecuteExecute':['Execute'],
  'Health regenerationHeal Execute':['Health regeneration','Heal','Execute'],
  'InvisibilityBonus AS Stealth':['Invisibility','Bonus AS','Stealth'],
  'Life StealHeal Execute Bonus AS':['Life Steal','Heal','Execute','Bonus AS'],
  'On-HitHeal':['On-Hit','Heal'],
  'ResurrectionHeal':['Resurrection','Heal'],
  'ScalingHeal Slow Execute':['Scaling','Heal','Slow','Execute'],
  'SpeedFear Speed':['Speed','Fear'],
  'SpeedHeal':['Speed','Heal'],
  'TakedownBonus AS Speed':['Takedown','Bonus AS','Speed'],
  'True DamageOn-Hit':['True Damage','On-Hit']
};
function normalizedTeamSkillTags(values=[]){return unique(values.flatMap(value=>TEAM_SKILL_TAG_REPAIRS[value]||[value]).map(value=>String(value||'').trim()).filter(Boolean))}
function skillTagTone(value=''){
  const name=slug(value),matches=(...terms)=>terms.some(term=>name.includes(slug(term)));
  if(matches('airborne','stun','root','charm','fear','suppress','taunt','knockup','knockdown','hard cc','hook'))return'tone-engage';
  if(matches('heal','shield','cleanse','immunity','resurrection','life steal','health regeneration'))return'tone-disengage';
  if(matches('burst damage','bonus damage','true damage','execute','takedown','on-hit'))return'tone-physical';
  if(matches('dash','blink','speed','displacement','mobility','stealth','invisibility'))return'tone-poke';
  if(matches('slow','silence','blind','ground','cripple','tether','polymorph'))return'tone-control';
  if(matches('teamfight','strong ult','aoe','uncancellable','reset'))return'tone-magic';
  if(matches('buff','bonus as','bonus armor','vision','sight','pet'))return'tone-support';
  if(matches('poke','clearwave','range'))return'tone-poke';
  return'tone-neutral';
}
function tacticalTag(value,hint=''){if(!value)return'';const iconKey=hint==='range'?'range':hint==='damage'?'damage':'combat',tone=hint==='skill'?skillTagTone(value):semanticTone(value,hint);return `<span class="tactical-tag ${tone} ${slug(value)}">${termIcon(value,'tactical-icon')||filterIcon(iconKey,value)}<b>${esc(value)}</b></span>`}
function isFlexChampion(c){return Boolean(c&&(c.profiles?.flex||settingRoles(c).length>1||(c.roles||[]).length>1))}
function tacticalTags(c){return unique([c?.combat?.primary,c?.combat?.secondary,c?.combat?.macro]).filter(Boolean)}
function championIdentityTags(c){return `<span class="team-identity-tags">${tacticalTag(c?.damage?.profile,'damage')}${tacticalTag(c?.range,'range')}</span>`}
function riotClassLine(c){const primary=c?.classification?.primary||'—',secondary=c?.classification?.secondary||'—',entry=(label,value)=>`<span><i class="riot-class-icon" aria-hidden="true">${filterIcon('className',value)}</i><small>${label}</small><b>${esc(value)}</b></span>`;return `<span class="riot-class-line" aria-label="${teamText('Main and secondary class','Class chính và phụ')}">${entry(teamText('MAIN','CHÍNH'),primary)}<em>/</em>${entry(teamText('SECONDARY','PHỤ'),secondary)}</span>`}
function championSkillTags(c){return normalizedTeamSkillTags((c?.abilities||[]).flatMap(ability=>ability.tags||[]))}
function primaryTeamSkillTags(c){
  const duplicates=new Set(tacticalTags(c).map(slug)),excluded=new Set(['engage','disengage','poke','catch','split','teamfight']),priority=['Strong Ult','Airborne','Stun','Root','Charm','Fear','Suppress','Hook','Shield','Heal','Cleanse','Execute','True Damage','Dash','Blink','Slow','Vision','Sight','Clearwave','AoE'];
  const rank=value=>{const index=priority.findIndex(item=>slug(item)===slug(value));return index<0?priority.length:index};
  return championSkillTags(c).filter(value=>!duplicates.has(slug(value))&&!excluded.has(slug(value))).sort((a,b)=>rank(a)-rank(b)||String(a).localeCompare(String(b))).slice(0,5);
}
function teamSkillTagText(value){return `<span class="team-skill-tag ${skillTagTone(value)}">${esc(value)}</span>`}
