function formationDepthTokens(c){const active=new Set(c?.combat?.positioning||[]),lines=['Frontline','Midline','Backline'],deepest=lines.reduce((result,position,index)=>active.has(position)?index:result,-1),tokens=deepest<0?[]:lines.slice(0,deepest+1).map(position=>active.has(position)?{position,label:formationName(position),active:true}:{position,label:'-',active:false});if(active.has('Flank'))tokens.push({position:'Flank',label:formationName('Flank'),active:true});return tokens}
function positionLine(c){const tokens=formationDepthTokens(c);return `<div class="position-line" aria-label="Combat line: ${esc((c.combat?.positioning||[]).join(', ')||'unspecified')}">${tokens.map(token=>`<span class="${token.active?'active':'placeholder'} position-${slug(token.position)}"><i></i><b>${esc(token.label)}</b></span>`).join('')||'<span class="placeholder"><i></i><b>—</b></span>'}</div>`}
