function referenceRoleRow(side,index){const c=byId(state[side][index]),role=roleForIndex(index),laneOk=!c||roleFits(c,index);return `<div class="role-row ${laneOk?'':'lane-warning'}" data-drop-slot="${side}:${index}" aria-label="Drop champion into ${side} ${role}"><div class="role-label role-slot">${roleIcon(role)}<span data-no-translate>${esc(role)}</span><small>ROLE</small></div><button type="button" draggable="${c?'true':'false'}" class="pick-cell ${c?'':'empty'}" data-picker="slot:${side}:${index}" data-drag-slot="${side}:${index}" aria-label="${c?`Change or drag ${c.name}`:`Choose champion for ${role}`}">${c?`${portrait(c)}<span class="pick-identity"><span class="pick-name-line"><b>${esc(c.name)}</b></span>${riotClassLine(c)}${championIdentityTags(c)}${phaseMicro(c)}${laneOk?'':'<strong class="lane-alert">! Off-role</strong>'}</span>${slotInsight(c,role)}`:`<span class="empty-pick-copy"><b>Choose ${esc(role)}</b><small>Click to open champion picker</small></span>`}</button><div class="pick-meta">${c?`<div class="combat-tag-line unified-tags">${tacticalTags(c).map(tacticalTag).join('')}</div>${positionLine(c)}`:`<div class="empty-meta"><span>TACTICAL PROFILE</span><small>Combat style and formation line appear here.</small></div>`}</div></div>`}
function teamBanPanel(side){if(!state.bansVisible)return'';const field=`${side}Bans`;return `<section class="team-ban-panel" aria-label="${side} team bans"><header><span>BANS</span><button type="button" data-action="reset-side-bans" data-side="${side}" ${state[field].some(Boolean)?'':'disabled'}>Reset bans</button></header><div>${state[field].map((id,index)=>{const c=byId(id);return `<button type="button" class="ban-slot ${c?'filled':''}" data-picker="ban:${field}:${index}" aria-label="${c?`Ban ${index+1}: ${c.name}. Activate to change`:`Choose ban ${index+1}`}">${c?portrait(c,'xs'):'<span aria-hidden="true">+</span>'}<small>${esc(c?.name||`Ban ${index+1}`)}</small>${c?`<i data-clear="${field}:${index}" aria-hidden="true">×</i>`:''}</button>`}).join('')}</div></section>`}
function teamProsCons(side){const m=teamMetrics(side),pros=[],cons=warnings(side),add=(condition,text)=>{if(condition&&!pros.includes(text))pros.push(text)};add(m.engage>=2,'Reliable engage');add(m.disengage>=2,'Strong disengage');add(m.catch>=2,'Pick potential');add(m.split>=2,'Side-lane pressure');add(m.poke>=2,'Poke setup');add(m.frontline>=2,'Stable frontline');add(m.magic&&m.physical,'Mixed damage');add(m.weightedPower.early>=m.weightedPower.late,'Early tempo');add(m.weightedPower.late>m.weightedPower.early,'Late scaling');return `<section class="team-pros-cons ${side}" aria-label="${side} strengths and weaknesses"><div><small>STRENGTHS</small><p>${(pros.slice(0,3).length?pros.slice(0,3):['Complete picks to calculate']).map(value=>`<span>${termIcon('Check','pill-icon')}${esc(value)}</span>`).join('')}</p></div><div><small>WEAKNESSES</small><p>${(cons.slice(0,3).length?cons.slice(0,3):['No critical gap detected']).map(value=>`<span>${termIcon('Warning','pill-icon')}${esc(value)}</span>`).join('')}</p></div></section>`}
function composition(side){return `<div class="team-composition team-panel ${side}"><div class="team-title"><span>TEAM ${side.toUpperCase()}</span><strong>${teamScore(side).toFixed(1)}<small>WEIGHTED POWER</small></strong></div>${teamBanPanel(side)}${teamProsCons(side)}<div class="team-roster">${ROLES.map((_,i)=>referenceRoleRow(side,i)).join('')}</div></div>`}
function laneFaceoff(index,compact=false,portraits=true){const b=byId(state.blue[index]),r=byId(state.red[index]),bs=lanePressure(b,r,ROLES[index]),rs=lanePressure(r,b,ROLES[index]),pct=b||r?Math.round(Math.max(15,Math.min(85,50+(bs-rs)*.8))):50,mark=bs===rs?'=':bs>rs?'›':'‹';return `<div class="lane-faceoff ${compact?'compact':''} ${portraits?'':'percent-only'}">${portraits?`<span>${b?portrait(b,compact?'xs':'sm'):''}<small>${esc(b?.name||'—')}</small></span>`:''}<b>${mark}<em>${pct}%</em></b>${portraits?`<span>${r?portrait(r,compact?'xs':'sm'):''}<small>${esc(r?.name||'—')}</small></span>`:''}</div>`}
function teamBalanceModel(){const lanes=ROLES.map((role,index)=>{const blueChampion=byId(state.blue[index]),redChampion=byId(state.red[index]);if(!blueChampion||!redChampion)return {role,blue:50,red:50,ready:false};const bluePressure=lanePressure(blueChampion,redChampion,role),redPressure=lanePressure(redChampion,blueChampion,role),blue=Math.round(Math.max(15,Math.min(85,50+(bluePressure-redPressure)*.8)));return {role,blue,red:100-blue,ready:true}}),ready=lanes.filter(lane=>lane.ready),blue=ready.length?Math.round(ready.reduce((sum,lane)=>sum+lane.blue,0)/ready.length):50,red=100-blue;return {lanes,blue,red,ready:ready.length}}
function faceoffRail(){const model=teamBalanceModel();return `<aside class="faceoff-rail team-win-rail" aria-label="Inferred lane win percentages"><header><span><small>BLUE</small><b>${model.blue}%</b></span><em>LANE<small>EDGE</small></em><span><small>RED</small><b>${model.red}%</b></span></header>${model.lanes.map((lane,index)=>{const blue=byId(state.blue[index]),red=byId(state.red[index]),winner=!lane.ready?null:lane.blue===lane.red?null:lane.blue>lane.red?blue:red,winnerSide=!lane.ready?'empty':lane.blue===lane.red?'even':lane.blue>lane.red?'blue':'red',edge=winner?`${winner.name} ahead`:lane.ready?'Even lane':'Waiting';return `<section class="${lane.ready?'ready':'empty'} edge-${winnerSide}"><small>${esc(lane.role)}</small><div>${blue?portrait(blue,'xs'):''}<b><span>${lane.blue}%</span><i>·</i><span>${lane.red}%</span></b>${red?portrait(red,'xs'):''}</div><em>${esc(edge)}</em></section>`}).join('')}<footer>${model.ready}/5 LANES<small>PRESSURE ESTIMATE</small></footer></aside>`}
function metricRow(label,key,a,b,max=5){const av=Number(a[key])||0,bv=Number(b[key])||0,winner=compareValue(av,bv);return `<div class="metric-row"><b>${esc(label)}</b><span class="metric-number blue">${av.toFixed(1)}</span><div class="dual-bar"><i style="width:${Math.min(50,av/max*50)}%"></i><i style="width:${Math.min(50,bv/max*50)}%"></i></div><span class="metric-number red">${bv.toFixed(1)}</span><em class="${winner}">${winner==='tie'?'Even':winner==='blue'?'Blue':'Red'}</em></div>`}
function laneRows(){return ROLES.map((role,i)=>{const a=byId(state.blue[i]),b=byId(state.red[i]);if(!a&&!b)return'';const av=a?phaseValue(a.power.early)+Number(a.ratings.damage||0):0,bv=b?phaseValue(b.power.early)+Number(b.ratings.damage||0):0;return `<div class="lane-row"><b>${role}</b><div>${a?portrait(a,'xs'):''}<span>${esc(a?.name||'Empty')}</span></div><em class="${compareValue(av,bv)}">${av===bv?'=':av>bv?'Blue advantage':'Red advantage'}</em><div>${b?portrait(b,'xs'):''}<span>${esc(b?.name||'Empty')}</span></div></div>`}).join('')}
function teamSummary(side){const m=teamMetrics(side),warn=warnings(side);return `<section class="summary-side ${side}"><h3>${side==='blue'?'Blue':'Red'} composition</h3><div class="summary-tags">${['engage','disengage','poke','split','catch'].map(k=>pill(`${k} ${m[k]}`,k)).join('')}</div><dl><div><dt>Damage</dt><dd>${m.damage.toFixed(1)}</dd></div><div><dt>Toughness</dt><dd>${m.toughness.toFixed(1)}</dd></div><div><dt>Control</dt><dd>${m.control.toFixed(1)}</dd></div><div><dt>Utility</dt><dd>${m.utility.toFixed(1)}</dd></div></dl><div class="warnings">${warn.map(x=>`<span>${esc(x)}</span>`).join('')||'<span class="ok">Basic composition is balanced</span>'}</div></section>`}
function winCondition(side,enemy){const m=teamMetrics(side),e=teamMetrics(enemy),lines=[];if(m.weightedPower.early>e.weightedPower.early)lines.push('Create early tempo and convert lane pressure into major objectives.');if(m.weightedPower.late>e.weightedPower.late)lines.push('Protect resources, avoid low-value trades, and fight around late-game carries.');if(m.engage>e.disengage)lines.push('Force fights proactively when the engage angle is clean.');if(m.poke>e.poke)lines.push('Chip health before objectives instead of instantly forcing a 5v5.');if(m.split>e.split)lines.push('Use side-lane pressure to stretch the enemy formation.');return lines.length?lines:['Stay grouped and win through cleaner teamfight execution.']}
function teamDeepAnalysis(side){const list=team(side),m=teamMetrics(side),den=Math.max(1,list.length),count=test=>list.filter(test).length,pct=n=>Math.round(n/den*100),basic=Math.round(list.reduce((n,c)=>n+(Number(c.damage.basicAttackShare)||0),0)/den*100),burst=count(c=>/burst/i.test(`${c.damage.profile} ${c.classification.secondary}`)),dps=count(c=>/dps|marksman|juggernaut/i.test(`${c.damage.profile} ${c.classification.primary}`));return `<section class="team-deep ${side}"><header><div><span>${side.toUpperCase()} SIDE</span><h3>Composition breakdown</h3></div><b>${list.length}/5</b></header><div class="profile-bars">${[['Early',Math.round(m.early/3*100)],['Late',Math.round(m.late/3*100)],['DPS',pct(dps)],['Burst',pct(burst)],['Melee',pct(m.melee)],['Ranged',pct(m.ranged)],['Physical',pct(m.physical)],['Magic',pct(m.magic)],['Basic attack',basic],['Abilities',Math.max(0,100-basic)]].map(([label,value])=>`<div><span>${esc(label)}</span><i><b style="width:${Math.min(100,value)}%"></b></i><em>${value}%</em></div>`).join('')}</div><div class="utility-strip">${[['Engage',m.engage],['Disengage',m.disengage],['Poke',m.poke],['Catch',m.catch],['Split',m.split],['CC',m.cc],['Heal',m.heal],['Shield',m.shield],['Mobility',m.mobilitySources]].map(([label,value])=>`<span><small>${label}</small><b>${value}</b></span>`).join('')}</div><div class="cc-table-wrap"><table class="data-table"><thead><tr><th>Role</th><th>Champion</th><th>Position</th><th>Combat / Macro</th><th>Class</th><th>Damage</th><th>Early</th><th>Mid</th><th>Late</th><th>Strong skill</th></tr></thead><tbody>${list.map(c=>`<tr><td>${esc(c.primaryRole)}</td><td>${portrait(c,'xs')}<b>${esc(c.name)}</b></td><td>${esc(c.combat.positioning.join(' · '))}</td><td>${esc([c.combat.primary,c.combat.secondary,c.combat.macro].filter(Boolean).join(' · '))}</td><td>${esc([c.classification.primary,c.classification.secondary].filter(Boolean).join(' · '))}</td><td>${esc(c.damage.profile)}</td><td>${esc(c.power.early)}</td><td>${esc(c.power.mid)}</td><td>${esc(c.power.late)}</td><td>${esc(c.abilities.filter(a=>a.tags.includes('Strong Ult')||a.tags.includes('TeamFight')).map(a=>`${a.slot} ${a.name}`).join(' · ')||'—')}</td></tr>`).join('')}</tbody></table></div><div class="team-guides">${list.map(c=>{const g=guideFor(c);return `<details><summary>${portrait(c,'xs')}<b>${esc(c.name)}</b><span>${esc(c.primaryRole)}</span></summary><div>${PHASES.map(p=>`<article><b>${p}</b><p>${esc(g.gamePlan?.[p]||'—')}</p><small>${esc(g.powerSpikes?.[p]||'—')}</small></article>`).join('')}</div></details>`}).join('')}</div></section>`}
function teamText(en,vi){return state.lang==='vi'?vi:en}
function teamPositionTags(c){const positions=c?.combat?.positioning||[],tokens=formationDepthTokens(c);return `<div class="team-position-tags" aria-label="${teamText('Formation positions','Vị trí đội hình')}: ${esc(positions.join(', ')||teamText('unspecified','chưa xác định'))}">${tokens.map(token=>`<span class="${token.active?`position-${slug(token.position)}`:'position-placeholder'}">${esc(token.label)}</span>`).join('')||'<span class="position-empty">—</span>'}</div>`}
function teamSheetBanSide(side){const field=`${side}Bans`,label=side==='blue'?teamText('BLUE TEAM BANS','BAN ĐỘI XANH'):teamText('RED TEAM BANS','BAN ĐỘI ĐỎ');return `<section class="team-sheet-bans ${side}" aria-label="${label}"><header><b>${label}</b><small>${state[field].filter(Boolean).length}/5</small></header><div>${state[field].map((id,index)=>{const c=byId(id);return `<button type="button" class="team-sheet-ban ${c?'filled':''}" data-picker="ban:${field}:${index}" aria-label="${c?`${teamText('Ban','Cấm')} ${index+1}: ${c.name}`:`${teamText('Choose ban','Chọn tướng cấm')} ${index+1}`}">${c?portrait(c,'lg'):'<span aria-hidden="true">+</span>'}<small>${esc(c?.name||`${teamText('Ban','Ban')} ${index+1}`)}</small>${c?`<i data-clear="${field}:${index}" aria-hidden="true">×</i>`:''}</button>`}).join('')}</div></section>`}
function teamSheetPick(side,index){const c=byId(state[side][index]),role=ROLES[index],laneOk=!c||roleFits(c,index),skillTags=c?primaryTeamSkillTags(c):[];return `<section class="team-sheet-side ${side} ${laneOk?'':'lane-warning'}" data-drop-slot="${side}:${index}"><button type="button" draggable="${c?'true':'false'}" class="team-sheet-pick ${c?'':'empty'}" data-picker="slot:${side}:${index}" data-drag-slot="${side}:${index}">${c?`${portrait(c,'lg')}<span class="team-sheet-identity">${riotClassLine(c)}<b>${esc(c.name)}</b>${championIdentityTags(c)}${phaseMicro(c)}${laneOk?'':'<strong>! Off-role</strong>'}</span>`:`<span class="team-sheet-empty"><b>${teamText('Choose champion','Chọn tướng')}</b><small data-no-translate>${esc(role)}</small></span>`}</button><div class="team-sheet-meta">${c?`<div class="combat-tag-line unified-tags">${tacticalTags(c).map(tacticalTag).join('')}</div>${teamPositionTags(c)}`:`<small>${teamText('Combat tags and formation appear after selection.','Tag giao tranh và vị trí sẽ hiện sau khi chọn.')}</small>`}</div><div class="team-sheet-skill-tags"><small>${teamText('KEY EFFECTS','HIỆU ỨNG CHÍNH')}</small><div class="team-skill-tag-line">${skillTags.map(teamSkillTagText).join('')||'<span class="position-empty">—</span>'}</div></div></section>`}
function teamSheetLane(index){const role=ROLES[index],model=teamBalanceModel().lanes[index],edge=!model.ready?teamText('WAITING','CHỜ CHỌN'):model.blue===model.red?teamText('EVEN','CÂN BẰNG'):model.blue>model.red?teamText('BLUE EDGE','XANH LỢI THẾ'):teamText('RED EDGE','ĐỎ LỢI THẾ');return `<article class="team-sheet-lane">${teamSheetPick('blue',index)}<div class="team-lane-center"><div class="team-lane-role">${roleIcon(role)}<b data-no-translate>${esc(role)}</b></div><span class="team-lane-percent"><i>${model.blue}%</i><b>VS</b><em>${model.red}%</em></span><small>${edge}</small></div>${teamSheetPick('red',index)}</article>`}
function myTeamMarker(side){const checked=state.perspective===side;return `<label class="my-team-check" title="${esc(teamText('Mark as my team','Đánh dấu là đội của tôi'))}"><input type="checkbox" data-my-team-side="${side}" ${checked?'checked':''}><i aria-hidden="true">✓</i><small>${teamText('MY TEAM','ĐỘI CỦA TÔI')}</small></label>`}
function teamSheetBoard(){const balance=teamBalanceModel();return `<section class="team-sheet-board"><div class="team-sheet-ban-grid">${teamSheetBanSide('blue')}<div class="team-sheet-score"><span><b>${balance.blue}%</b><small>${teamText('BLUE','XANH')}</small></span><strong>VS</strong><span><b>${balance.red}%</b><small>${teamText('RED','ĐỎ')}</small></span></div>${teamSheetBanSide('red')}</div><header class="team-sheet-title"><b><span>${teamText('TEAM BLUE','ĐỘI XANH')}</span>${myTeamMarker('blue')}</b><span>${teamText('LANE MATCHUPS','ĐỐI ĐẦU THEO LANE')}</span><b><span>${teamText('TEAM RED','ĐỘI ĐỎ')}</span>${myTeamMarker('red')}</b></header><div class="team-sheet-roster">${ROLES.map((_,index)=>teamSheetLane(index)).join('')}</div></section>`}
function teamContributorFaces(side,test){const hits=team(side).filter(test);return `<div class="team-matrix-faces ${side}">${hits.map(c=>`<span title="${esc(c.name)}">${portrait(c,'xs')}<small>${esc(c.name)}</small></span>`).join('')||'<em>—</em>'}</div>`}
function teamMatrixRow(label,test,tone=slug(label)){const blue=team('blue').filter(test).length,red=team('red').filter(test).length;return `<div class="team-matrix-row tone-${slug(tone)}">${teamContributorFaces('blue',test)}<b>${blue}</b><span>${termIcon(label,'matrix-icon')||filterIcon('combat',label)}<strong>${esc(label)}</strong></span><b>${red}</b>${teamContributorFaces('red',test)}</div>`}
function teamMatrixGroup(title,subtitle,rows){return `<section class="team-matrix-group"><header><h3>${esc(title)}</h3><small>${esc(subtitle)}</small></header><div>${rows.map(([label,test,tone])=>teamMatrixRow(label,test,tone)).join('')}</div></section>`}
function teamWorkbookMatrices(){const hardCc=c=>(c.abilities||[]).some(a=>(a.tags||[]).some(tag=>/airborne|charm|fear|root|sleep|stun|suppression|taunt|knock|polymorph|cc hard/i.test(tag))),abilityShare=c=>(Number(c.damage?.basicAttackShare)||0),groups=[
  [teamText('Combat identity','Bản sắc giao tranh'),teamText('Engage, counter-engage and map pressure','Lao vào, phản lao vào và áp lực bản đồ'),[['Engage',c=>hasTeamTag(c,'Engage'),'engage'],['Disengage',c=>hasTeamTag(c,'Disengage|Peel'),'disengage'],['Poke',c=>hasTeamTag(c,'Poke'),'poke'],['Split',c=>hasTeamTag(c,'Split'),'split'],['Catch',c=>hasTeamTag(c,'Catch|Pick'),'catch']]],
  [teamText('Formation lines','Tuyến đội hình'),teamText('Exact contributors by combat position','Tướng đóng góp theo đúng vị trí giao tranh'),[['Frontline',c=>c.combat.positioning.includes('Frontline'),'frontline'],['Midline',c=>c.combat.positioning.includes('Midline'),'midline'],['Backline',c=>c.combat.positioning.includes('Backline'),'backline'],['Flank',c=>c.combat.positioning.includes('Flank'),'flank']]],
  [teamText('Range & damage','Tầm đánh và sát thương'),teamText('Composition shape from champion records','Cấu trúc đội hình từ dữ liệu tướng'),[['Melee',c=>c.range==='Melee','melee'],['Ranged',c=>c.range==='Ranged','ranged'],['Physical',c=>/physical|ad/i.test(`${c.damage.type} ${c.damage.profile}`),'physical'],['Magic',c=>/magic|ap/i.test(`${c.damage.type} ${c.damage.profile}`),'magic']]],
  [teamText('Attack dependency','Phụ thuộc đòn đánh'),teamText('Ability, hybrid and basic-attack sources','Nguồn kỹ năng, lai và đánh thường'),[['Basic attack',c=>abilityShare(c)>TEAM_RULES.hybridAttackMaxShare,'basicattack'],['Hybrid',c=>abilityShare(c)>TEAM_RULES.basicAttackMaxShare&&abilityShare(c)<=TEAM_RULES.hybridAttackMaxShare,'hybrid'],['Ability',c=>abilityShare(c)<=TEAM_RULES.basicAttackMaxShare,'ability']]],
  [teamText('Fight & macro triggers','Điều kiện giao tranh và macro'),teamText('Only champions meeting each data rule are shown','Chỉ hiện tướng đạt đúng điều kiện dữ liệu'),[['Teamfight',c=>hasTeamTag(c,'TeamFight'),'teamfight'],['Dive',c=>hasTeamTag(c,'Dive|Dash'),'dive'],['DPS carry',c=>Boolean(c.profiles?.carry||c.profiles?.hyperCarry||c.classification.primary==='Marksman'),'dpscarry'],['Assassin',c=>/assassin|slayer/i.test(`${c.classification.primary} ${c.classification.secondary}`),'assassin'],['CC Hard',hardCc,'cchard'],['Clearwave',c=>(Number(c.ratings.clearwave)||0)>=TEAM_RULES.waveClearStrongThreshold,'clearwave'],['Tower',c=>(Number(c.ratings.tower)||0)>=TEAM_RULES.towerStrongThreshold,'tower'],['Strong Ult',c=>(c.abilities||[]).some(a=>(a.tags||[]).includes('Strong Ult')),'strongult']]],
  [teamText('Utility sources','Nguồn công cụ'),teamText('Champion-level capability contributors','Tướng cung cấp từng loại công cụ'),[['Heal',c=>hasTeamTag(c,'Heal'),'heal'],['Shield',c=>hasTeamTag(c,'Shield'),'shield'],['CC Hard',hardCc,'cchard'],['Vision',c=>hasTeamTag(c,'Vision|Sight'),'vision'],['Buff',c=>hasTeamTag(c,'Buff'),'buff'],['Slow',c=>hasTeamTag(c,'Slow'),'slow']]]
];return `<section class="team-workbook-matrices"><div class="section-head"><h2>${teamText('Composition matrices','Ma trận đội hình')}</h2><span>${teamText('Count and exact champion contributors','Số lượng và đúng tướng đóng góp')}</span></div><div>${groups.map(group=>teamMatrixGroup(...group)).join('')}</div></section>`}
function teamFocusControls(){const lanes=[['Top','Top'],['Jungle','Jungle'],['Mid','Mid'],['Bot',teamText('Bot (AD + Support)','Bot (AD + Hỗ trợ)')]];return `<section class="team-focus-controls"><div><small>${teamText('LANE DETAIL','CHI TIẾT LANE')}</small><div class="segmented">${lanes.map(([id,label])=>`<button type="button" data-team-focus-lane="${id}" class="${state.teamFocusLane===id?'active':''}" aria-pressed="${state.teamFocusLane===id}">${id!=='Bot'?roleIcon(id):filterIcon('role','AD')}<span data-no-translate>${esc(label)}</span></button>`).join('')}</div></div><div><small>${teamText('MATCH PHASE','GIAI ĐOẠN TRẬN')}</small><div class="segmented">${PHASES.map(phase=>`<button type="button" data-team-focus-phase="${phase}" class="${state.teamFocusPhase===phase?'active':''}" aria-pressed="${state.teamFocusPhase===phase}">${termIcon(phase,'phase-icon')}${teamText(phase[0].toUpperCase()+phase.slice(1),phase==='early'?'Đầu trận':phase==='mid'?'Giữa trận':'Cuối trận')}</button>`).join('')}</div></div></section>`}
