function teamFocusPanel(){const indexes=state.teamFocusLane==='Bot'?[3,4]:[Math.max(0,ROLES.indexOf(state.teamFocusLane))];return `<section class="team-focus-panel">${teamFocusControls()}<div class="team-focus-list">${indexes.map(teamFocusMatchup).join('')}</div></section>`}
function compactGuideText(value,max=360){const text=String(value||'').replace(/\s+/g,' ').trim();if(text.length<=max)return text;const clipped=text.slice(0,max),sentence=Math.max(clipped.lastIndexOf('. '),clipped.lastIndexOf('! '),clipped.lastIndexOf('? '));return `${clipped.slice(0,sentence>max*.55?sentence+1:max).trim()}…`}
