function teamStrengthWeaknessPanel(){return `<section class="team-strength-panel"><div class="section-head"><div><small>${teamText('CHAMPION MIRROR','ĐỐI CHIẾU TƯỚNG')}</small><h2>${teamText('Strengths and weaknesses','Điểm mạnh và điểm yếu')}</h2></div><span>${teamText('Each lane reads outward from the center axis.','Mỗi lane được trình bày đối xứng từ trục giữa ra ngoài.')}</span></div><div class="team-strength-list">${ROLES.map((role,index)=>`<section class="team-strength-lane">${teamStrengthCard('blue',index)}<div class="team-strength-axis">${roleIcon(role)}<b>${esc(role)}</b></div>${teamStrengthCard('red',index)}</section>`).join('')}</div></section>`}
function renderTeam(){return pageIntro(teamText('Team composition analyzer','Phân tích đội hình'),teamText('Build both teams, compare exact sheet identities, then inspect one lane and match phase at a time.','Xây dựng hai đội, đối chiếu đúng các hệ trong sheet rồi xem từng lane và giai đoạn trận.'))+teamSheetBoard()+teamWorkbookMatrices()+teamStrengthWeaknessPanel()+teamFocusPanel()}
const TEAMFIGHT_ARCHETYPE_ROOT='assets/teamfight-archetypes/';
