const RIFT_COORDINATES={camps:{blue:{gromp:[15.4,43.8],bluesentinel:[25.4,46.5],murkwolves:[25.6,56.6],raptors:[47.5,64.6],redbrambleback:[52.5,74.2],krugs:[57.2,83]},red:{gromp:[85.7,56.6],bluesentinel:[74.6,53.3],murkwolves:[74.6,43.8],raptors:[52.7,35.4],redbrambleback:[47.9,25.8],krugs:[43.2,17.6]}},scuttle:{top:[29.1,35.4],bot:[72.9,65.8]},lanes:{top:[13.7,15.6],mid:[50.4,50.8],bot:[85.9,85]},objectives:{baron:[13.7,15.6],dragon:[85.9,85]}};
const RIFT_CAMP_NAMES={gromp:'Gromp',bluesentinel:'Bluesentinel',murkwolves:'Murkwolves',raptors:'Raptors',redbrambleback:'Redbrambleback',krugs:'Krugs'};
const JUNGLE_ROUTE_SHEET_URL='https://docs.google.com/spreadsheets/d/1L2mUP2Q0OGEFKf4OmZZSGxcv0VlZDpc890UWrmRgCFI/edit#gid=0';
function routeLaneTokens(value=''){return String(value).split(/[,/|]+/).map(x=>x.trim()).filter(x=>/^(top|mid|bot)$/i.test(x)).map(x=>x[0].toUpperCase()+x.slice(1).toLowerCase())}
function routeLaneForSide(lane,side){if(side!=='red')return lane;if(lane==='Top')return'Bot';if(lane==='Bot')return'Top';return lane}
function routeLaneSummary(route,side){const lanes=unique([...routeLaneTokens(route.gankSoon),...routeLaneTokens(route.gankLane)].map(lane=>routeLaneForSide(lane,side)));return lanes.join(' → ')||'Flexible'}
