function nearestLane(candidates,previous){if(!previous||candidates.length<2)return candidates[0]||'Mid';return candidates.reduce((best,lane)=>{const point=RIFT_COORDINATES.lanes[slug(lane)],bestPoint=RIFT_COORDINATES.lanes[slug(best)],distance=p=>Math.hypot(p[0]-previous[0],p[1]-previous[1]);return distance(point)<distance(bestPoint)?lane:best},candidates[0])}
function routeGankLane(route,side,gankIndex,previous){const early=routeLaneTokens(route.gankSoon).map(lane=>routeLaneForSide(lane,side)),later=routeLaneTokens(route.gankLane).map(lane=>routeLaneForSide(lane,side));if(gankIndex===0&&early.length)return early[0];return nearestLane(later.length?later:early,previous)}
function routeCoordinate(step,side='blue',route={},gankIndex=0,previous=null){const key=slug(step),enemy=/^enemy/.test(String(step).trim().toLowerCase())||/enemy/.test(key),campSide=enemy?(side==='blue'?'red':'blue'):side;if(/riftscuttler|scuttle|scuttler/.test(key))return RIFT_COORDINATES.scuttle[slug(routeScuttleLane(route,side))];if(/gank|dive/.test(key))return RIFT_COORDINATES.lanes[slug(routeGankLane(route,side,gankIndex,previous))]||RIFT_COORDINATES.lanes.mid;if(/invade|steal/.test(key))return side==='blue'?RIFT_COORDINATES.camps.red.redbrambleback:RIFT_COORDINATES.camps.blue.redbrambleback;const campKey=key.includes('bluebuff')?'bluesentinel':key.includes('redbuff')?'redbrambleback':key.includes('wolves')?'murkwolves':Object.keys(RIFT_CAMP_NAMES).find(name=>key.includes(name));if(campKey)return RIFT_COORDINATES.camps[campSide][campKey];if(/dragon/.test(key))return RIFT_COORDINATES.objectives.dragon;if(/baron|herald/.test(key))return RIFT_COORDINATES.objectives.baron;return previous||[50,50]}
function routeStepType(step=''){const key=slug(step);if(/gank|dive/.test(key))return'gank';if(/dragon|herald|baron|rift|scuttle|voidgrubs/.test(key))return'objective';if(/invade|steal|^enemy/.test(key)||String(step).trim().toLowerCase().startsWith('enemy '))return'invade';return'camp'}
