function abilityRecordByName(c,name){const key=slug(name),pool=[...(c?.abilities||[])];if(c?.id==='kled'){const skaarl=byId('kledskaarl');if(skaarl)pool.push(...(skaarl.abilities||[]))}return pool.map(ability=>normalizedAbility(c,ability)).find(record=>slug(record.name)===key||slug(record.name).includes(key)||key.includes(slug(record.name)))}
function kitMini(record,label){return record?`<span class="special-kit-chip">${record.images?.[0]?`<img src="${esc(record.images[0])}" alt="${esc(record.name)}" loading="lazy" decoding="async">`:`<i>${esc(record.slot?.[0]||'?')}</i>`}<b>${esc(record.name)}</b><small>${esc(record.slot||label||teamText('Skill','Kỹ năng'))}</small></span>`:`<span class="special-kit-chip missing"><i>?</i><b>${esc(label||teamText('Missing','Thiếu dữ liệu'))}</b><small>${teamText('No local record','Không có bản ghi cục bộ')}</small></span>`}
function inferredVariantGroups(c){const records=dedupedSkillRecords(c),alternate=records.filter(record=>(record.form&&record.form!=='base')||/^Variant/i.test(record.slot||'')),splitMain=records.filter(record=>/\/| or | form/i.test(record.name||''));if(!alternate.length&&!splitMain.length)return null;return {title:'Detected alternate forms',titleVi:'Phát hiện các dạng phụ',source:'Local Skill data',sourceVi:'Dữ liệu Skill cục bộ',summary:`${records.length} visible skills are preserved from ${(c.abilities||[]).length} source records. Variant rows and names containing “/” are grouped so alternate forms remain readable.`,summaryVi:`Hiện có ${records.length} kỹ năng hiển thị từ ${(c.abilities||[]).length} bản ghi gốc. Các dòng Variant và tên có dấu “/” được gom lại để không mất dạng phụ.`,groups:[{name:'Main kit has split forms',nameVi:'Bộ kỹ năng chính có nhiều trạng thái',tone:'hybrid',trigger:'Skill names contain multiple halves or states',triggerVi:'Tên kỹ năng có nhiều nửa hoặc nhiều trạng thái',records:splitMain,notes:['Hover or open each card for detailed tags and cooldowns.'],notesVi:['Di chuột hoặc mở card để đọc tag và hồi chiêu chi tiết.']},{name:'Extra variant records',nameVi:'Bản ghi dạng phụ bổ sung',tone:'variant',trigger:'Variant rows from the Skill sheet',triggerVi:'Các dòng Variant trong sheet Skill',records:alternate,notes:['These records are often lost when only Passive + Q/W/E/R are kept.'],notesVi:['Phần này thường bị ẩn nếu chỉ giữ Nội tại + Q/W/E/R.']}].filter(group=>group.records?.length)}}
function specialKitPanel(c){const kit=SPECIAL_KIT_NOTES[c.id]||inferredVariantGroups(c);if(!kit)return'';const vi=state.lang==='vi',title=vi?(kit.titleVi||kit.title):(kit.titleEn||kit.title),source=vi?(kit.sourceVi||kit.source):(kit.sourceEn||kit.source),summary=vi?(kit.summaryVi||kit.summary):(kit.summaryEn||kit.summary);return `<section class="special-kit-panel"><div class="section-head"><h3>${teamText('Special kit / forms','Bộ kỹ năng / dạng đặc biệt')}</h3><span>${esc(source||teamText('Local data','Dữ liệu cục bộ'))}</span></div><header><b>${esc(title)}</b><p>${esc(summary||teamText('Champion has multiple readable skill states.','Tướng có nhiều trạng thái kỹ năng cần hiển thị riêng.'))}</p></header><div class="special-kit-grid">${(kit.groups||[]).map(group=>{const records=group.records||group.abilities?.map(name=>abilityRecordByName(c,name)).filter(Boolean)||[],name=vi?(group.nameVi||group.name):(group.nameEn||group.name),trigger=vi?(group.triggerVi||group.trigger):(group.triggerEn||group.trigger),notes=vi?(group.notesVi||group.notes):(group.notesEn||group.notes);return `<article class="${esc(group.tone||'default')}"><div class="special-kit-title"><strong>${esc(name)}</strong><small>${esc(trigger||teamText('Alternate form','Dạng phụ'))}</small></div><div class="special-kit-abilities">${records.length?records.map(record=>kitMini(record)).join(''):(group.abilities||[]).map(abilityName=>kitMini(null,abilityName)).join('')}</div>${notes?.length?`<ul>${notes.map(note=>`<li>${esc(note)}</li>`).join('')}</ul>`:''}</article>`}).join('')}</div></section>`}
function championProfileRadar(c){const ratings=c.ratings||{},magicBias=/magic|ap/i.test(`${c.damage?.type||''} ${c.damage?.profile||''}`),magicScore=magicBias?ratings.damage:Math.max(Number(ratings.control)||0,Number(ratings.utility)||0)-1,stats=[['Attack','Tấn công','ATK',ratings.damage,'Physical'],['Defense','Chống chịu','DEF',ratings.toughness,'Tank'],['Magic','Phép thuật','MAG',magicScore,'Magic'],['Control','Khống chế','CC',ratings.control,'Vision'],['Mobility','Cơ động','MOV',ratings.mobility,'Mobility']].map(([label,labelVi,short,value,icon])=>({label:teamText(label,labelVi),short,value:Math.max(0,Math.min(5,Number(value)||0)),icon})),points=stats.map((stat,index)=>radarPoint(stat.value,index,stats.length)).join(' '),grid=[1,2,3,4,5].map(level=>`<polygon points="${stats.map((_,index)=>radarPoint(level,index,stats.length)).join(' ')}"></polygon>`).join(''),spokes=stats.map((_,index)=>`<line x1="60" y1="60" x2="${radarPoint(5,index,stats.length).split(',')[0]}" y2="${radarPoint(5,index,stats.length).split(',')[1]}"></line>`).join(''),total=Math.round(stats.reduce((sum,stat)=>sum+stat.value,0)/stats.length*20);return `<section class="champion-radar-card"><div class="section-head"><h3>${teamText('Combat profile','Hồ sơ giao tranh')}</h3><span>${teamText('5-axis rating','Đánh giá 5 trục')}</span></div><div class="champion-radar-wrap"><span class="radar-stage"><span class="radar-icons">${stats.map((stat,index)=>`<span class="radar-icon radar-icon-${index}" title="${esc(`${stat.label}: ${stat.value.toFixed(1)}/5`)}">${filterIcon('className',stat.icon)}<small>${esc(stat.short)}</small></span>`).join('')}</span><svg class="radar-orb" viewBox="0 0 120 120" aria-hidden="true" focusable="false"><circle class="radar-back" cx="60" cy="60" r="55"></circle><g class="radar-grid">${grid}${spokes}</g><polygon class="radar-fill" points="${points}"></polygon><polygon class="radar-stroke" points="${points}"></polygon><circle class="radar-core" cx="60" cy="60" r="13"></circle><circle class="radar-dot" cx="60" cy="60" r="6"></circle></svg><span class="radar-score"><b>${total}</b><small>${teamText('profile','hồ sơ')}</small></span></span><div class="champion-radar-values">${stats.map(stat=>`<span><i>${filterIcon('className',stat.icon)}</i><small>${esc(stat.label)}</small><b>${stat.value.toFixed(0)}</b></span>`).join('')}</div></div></section>`}
function abilityKitCard(record,c,mode='large'){const rank=strongSkillRank(c,record),strong=rank>=0,forms=[...(record.forms||[])],image=record.images?.[0],extra=(record.images||[]).slice(1,3),tags=unique([...(record.tags||[]),...(record.ccTypes||[])]).slice(0,12);return `<article class="wiki-skill-card ${mode} slot-${slug(record.slot)} ${strong?'strong-skill':''} ${record.impact==='High'?'high-impact':record.impact==='Medium'?'mid-impact':''}"><header><span class="wiki-skill-slot">${esc(record.slot)}</span>${image?`<img src="${esc(image)}" alt="${esc(record.name)}" width="64" height="64" loading="lazy" decoding="async">`:`<i>${esc(record.slot[0]||'?')}</i>`}<div><small>${esc(record.impact||'Standard')} impact${forms.length?` · ${forms.map(esc).join(' / ')}`:''}</small><h3>${esc(record.name)}</h3><em>${esc(record.cooldown||'No cooldown data')}</em></div>${strong?`<strong class="strong-order">Strong #${rank+1}</strong>`:''}</header>${extra.length?`<div class="wiki-skill-forms">${extra.map(src=>`<img src="${esc(src)}" alt="${esc(record.name)} form" width="28" height="28" loading="lazy" decoding="async">`).join('')}</div>`:''}<div class="wiki-skill-meta"><span><small>Cooldown</small><b>${esc(record.cooldown||'—')}</b></span><span><small>CC</small><b>${record.ccTypes?.length?record.ccTypes.map(esc).join(' / '):'—'}</b></span><span><small>Tags</small><b>${tags.length}</b></span></div><div class="wiki-skill-tags">${tags.map(tag=>pill(tag,semanticTone(tag))).join('')||'<span class="muted">No tags</span>'}</div></article>`}
function abilityKitPanel(c){const records=kitRecords(c),passive=records.find(record=>record.slot==='Passive'),main=primarySkillRecords(c),tags=unique(records.flatMap(record=>record.tags||[]));return `<section class="ability-kit-panel"><div class="section-head"><h3>${teamText('Ability kit','Bộ kỹ năng')}</h3><span>${teamText('Passive + 4 main skills · cooldown and tags first','Nội tại + 4 kỹ năng chính · ưu tiên hồi chiêu và tag')}</span></div><div class="ability-kit-top">${passive?abilityKitCard(passive,c,'passive'):''}<div class="ability-bar">${main.map(record=>`<span class="${strongSkillRank(c,record)>=0?'active':''}">${record.images?.[0]?`<img src="${esc(record.images[0])}" alt="${esc(record.name)}">`:`<i>${esc(record.slot)}</i>`}<b>${esc(record.slot)}</b><small>${esc(record.cooldown||'—')}</small></span>`).join('')}</div></div><div class="wiki-skill-grid">${main.map(record=>abilityKitCard(record,c,'large')).join('')}</div><section class="skill-tag-standard"><div class="section-head"><h3>${teamText('Standard tags','Tag chuẩn hóa')}</h3><span>${tags.length} ${teamText('normalized skill tags','tag kỹ năng đã chuẩn hóa')}</span></div><div>${standardTagGroups(records,c)||`<p class="empty">${teamText('No normalized tags.','Không có tag chuẩn hóa.')}</p>`}</div></section></section>`}
const abilityKitPanelWithoutForms=abilityKitPanel;
abilityKitPanel=function(c){const html=abilityKitPanelWithoutForms(c),panel=specialKitPanel(c);return panel?html.replace('<div class="wiki-skill-grid">',`${panel}<div class="wiki-skill-grid">`):html}
function skillDetailValue(value){return value==null||String(value).trim()===''?'—':String(value).trim()}
function skillDetailRows(record){const d=record.details||{},rows=[
  [teamText('Cooldown','Hồi chiêu'),d.cooldown||record.cooldown],
  [teamText('Cost','Tiêu hao'),d.resource||d.costType||d.cost],
  [teamText('Range','Tầm dùng'),d.range],
  [teamText('Max rank','Cấp tối đa'),d.maxRank]
];return rows.filter(([,value])=>skillDetailValue(value)!=='—').map(([label,value])=>`<span><small>${esc(label)}</small><b>${esc(skillDetailValue(value))}</b></span>`).join('')}
function skillLevelTips(record){const tips=Array.isArray(record.details?.levelTips)?record.details.levelTips.filter(tip=>skillDetailValue(tip.label)!=='—'||skillDetailValue(tip.effect)!=='—').slice(0,4):[];return tips.length?`<div class="wiki-skill-leveltips">${tips.map(tip=>`<span><b>${esc(skillDetailValue(tip.label))}</b><small>${esc(skillDetailValue(tip.effect))}</small></span>`).join('')}</div>`:''}
function skillEffectBurn(record){const effects=Array.isArray(record.details?.effectBurn)?record.details.effectBurn.filter(value=>value&&value!=='0').slice(0,6):[];return effects.length?`<div class="wiki-skill-effects">${effects.map(value=>`<span>${esc(value)}</span>`).join('')}</div>`:''}
function skillSummary(record){const text=record.details?.summary||record.details?.tooltip||'';return text?`<p class="wiki-skill-summary">${esc(text)}</p>`:''}
abilityKitCard=function(record,c,mode='large'){const rank=strongSkillRank(c,record),strong=rank>=0,forms=[...(record.forms||[])],image=record.images?.[0],extra=(record.images||[]).slice(1,3),tags=unique([...(record.tags||[]),...(record.ccTypes||[])]).slice(0,12),detailRows=skillDetailRows(record),impact=record.impact||'Standard',impactVi={High:'Cao',Medium:'Trung bình',Standard:'Tiêu chuẩn'}[impact]||impact;return `<article class="wiki-skill-card ${mode} slot-${slug(record.slot)} ${strong?'strong-skill':''} ${record.impact==='High'?'high-impact':record.impact==='Medium'?'mid-impact':''}" data-hover-skill="${esc(`${c?.id||record.championId||''}:${record.id||record.name}`)}"><header><span class="wiki-skill-slot">${esc(record.slot)}</span>${image?`<img src="${esc(image)}" alt="${esc(record.name)}" width="64" height="64" loading="lazy" decoding="async">`:`<i>${esc(record.slot[0]||'?')}</i>`}<div><small>${esc(teamText(impact,impactVi))} ${teamText('impact','ảnh hưởng')}${forms.length?` · ${forms.map(esc).join(' / ')}`:''}</small><h3>${esc(record.name)}</h3><em>${esc(record.cooldown||record.details?.cooldown||teamText('No cooldown data','Không có dữ liệu hồi chiêu'))}</em></div>${strong?`<strong class="strong-order">${teamText('Strong','Mạnh')} #${rank+1}</strong>`:''}</header>${extra.length?`<div class="wiki-skill-forms">${extra.map(src=>`<img src="${esc(src)}" alt="${esc(record.name)} ${teamText('form','dạng')}" width="28" height="28" loading="lazy" decoding="async">`).join('')}</div>`:''}${skillSummary(record)}<div class="wiki-skill-meta">${detailRows||`<span><small>${teamText('Cooldown','Hồi chiêu')}</small><b>${esc(record.cooldown||'—')}</b></span>`}<span><small>CC</small><b>${record.ccTypes?.length?record.ccTypes.map(esc).join(' / '):'—'}</b></span><span><small>Tag</small><b>${tags.length}</b></span></div>${skillLevelTips(record)}${skillEffectBurn(record)}<div class="wiki-skill-tags">${tags.map(tag=>pill(tag,semanticTone(tag))).join('')||`<span class="muted">${teamText('No tags','Không có tag')}</span>`}</div></article>`}
function championSkillPanel(c){return abilityKitPanel(c)}
function skillCard(record){const c=byId(record.championId)||CHAMPIONS.find(champion=>(champion.abilities||[]).some(ability=>ability.name===record.name))||CHAMPIONS[0];return abilityKitCard(record,c,'compact')}
function skillWorkbookPanel(c){const records=dedupedSkillRecords(c),rawCount=(c.abilities||[]).length,tags=unique(records.flatMap(record=>record.tags||[])).sort(),cc=unique(records.flatMap(record=>record.ccTypes||[])).sort(),high=records.filter(record=>record.impact==='High').length,extra=records.filter(record=>!['Passive','Q','W','E','R'].includes(record.slot)||!primarySkillRecords(c).some(main=>main.slot===record.slot&&main.name===record.name));return `<main class="skill-profile skill-workbook-profile"><section class="skill-hero">${portrait(c,'lg')}<div><span>${esc(c.classification.primary)} · ${esc(c.roles.join(' / '))}</span><h2>${esc(c.name)}</h2><p>${records.length} ${teamText('visible skills','kỹ năng hiển thị')} · ${rawCount-records.length} ${teamText('duplicate/form records merged','bản ghi trùng hoặc dạng phụ đã gộp')} · ${tags.length} tag</p></div><aside><span><small>${teamText('High impact','Ảnh hưởng cao')}</small><b>${high}</b></span><span><small>${teamText('CC types','Loại CC')}</small><b>${cc.length}</b></span><span><small>${teamText('Cooldown rows','Dòng hồi chiêu')}</small><b>${records.filter(record=>String(record.cooldown||'').trim()).length}</b></span></aside></section>${abilityKitPanel(c)}<section class="skill-card-section secondary-skill-records"><div class="section-head"><h3>${teamText('Extra forms / merged records','Dạng phụ / bản ghi đã gộp')}</h3><span>${teamText('Alternate forms remain below the 4-skill kit','Các dạng phụ vẫn được giữ dưới bộ 4 kỹ năng chính')}</span></div><div class="skill-card-grid">${extra.map(record=>skillCard(record)).join('')||`<p class="empty">${teamText('No extra forms beyond the main kit.','Không có dạng phụ ngoài bộ kỹ năng chính.')}</p>`}</div></section></main>`}
function renderChampions(){const c=byId(state.focus)||CHAMPIONS[0],guide=guideFor(c),stats=Object.entries(c.baseStats||{}).filter(([,v])=>v!=null),empty=teamText('No data available.','Không có dữ liệu.'),phaseNames={early:teamText('Early','Đầu trận'),mid:teamText('Mid','Giữa trận'),late:teamText('Late','Cuối trận')};return pageIntro(teamText('Champion library','Thư viện tướng'),teamText('Wiki-style champion sheet: ability kit first, readable tags, profile radar and strategy notes.','Hồ sơ tướng dạng wiki: ưu tiên bộ kỹ năng, tag dễ đọc, radar và ghi chú chiến thuật.'))+`<div class="library-layout champion-wiki-layout">${libraryList('champions',c.id)}<main class="champion-profile champion-wiki-profile">${focusDetail(c)}${abilityKitPanel(c)}${championProfileRadar(c)}<section class="profile-section profile-meta"><span><small>Patch</small><b>${esc(c.metadata?.patch||'—')}</b></span><span><small>${teamText('Release year','Năm ra mắt')}</small><b>${esc(c.metadata?.releaseYear||'—')}</b></span><span><small>Tier</small><b>${esc(c.tier||'—')}</b></span><span><small>${teamText('Difficulty','Độ khó')}</small><b>${esc(c.difficulty??'—')}</b></span><span><small>${teamText('Roles','Vai trò')}</small><b>${esc(c.roles.join(' · '))}</b></span><span><small>${teamText('Range','Tầm đánh')}</small><b>${esc(c.range)}</b></span></section><section class="profile-section"><h3>${teamText('Base stats','Chỉ số cơ bản')}</h3><div class="stat-grid">${stats.map(([key,value])=>`<span><small>${esc(key)}</small><b>${esc(value)}</b></span>`).join('')}</div></section><section class="profile-section"><h3>${teamText('Strengths & weaknesses','Điểm mạnh và điểm yếu')}</h3><div class="guide-grid"><p>${esc(guide.strengths||empty)}</p><p>${esc(guide.weaknesses||empty)}</p></div></section><section class="profile-section"><h3>${teamText('Game plan','Kế hoạch trận đấu')}</h3><div class="plan-grid">${PHASES.map(p=>`<article><b>${phaseNames[p]}</b><p>${esc(guide.gamePlan?.[p]||empty)}</p></article>`).join('')}</div></section><section class="profile-section"><h3>${teamText('Power spikes','Mốc sức mạnh')}</h3><div class="plan-grid spikes">${PHASES.map(p=>`<article><b>${phaseNames[p]}</b><p>${esc(guide.powerSpikes?.[p]||empty)}</p></article>`).join('')}</div></section></main></div>`}
function renderSkills(){const c=byId(state.focus)||CHAMPIONS[0];return pageIntro(teamText('Skill library','Thư viện kỹ năng'),teamText('Champion kit view with Passive + Q/W/E/R, strong-skill highlight, cooldowns and normalized tags.','Bộ kỹ năng gồm Nội tại + Q/W/E/R, làm nổi kỹ năng mạnh, hồi chiêu và tag chuẩn hóa.'))+`<div class="library-layout skill-library-layout">${libraryList('skills',c.id)}${skillWorkbookPanel(c)}</div>`}
function renderChampionsFull(){const c=byId(state.focus)||CHAMPIONS[0];return afterPageIntro(renderChampions(),libraryCoveragePanel('champions'))+workbookChampionPanel(c)}
function renderSkillsFull(){const c=byId(state.focus)||CHAMPIONS[0];return pageIntro(teamText('Skill library','Thư viện kỹ năng'),teamText('Champion kit view with Passive + Q/W/E/R, strong-skill highlight, cooldowns and normalized tags.','Bộ kỹ năng gồm Nội tại + Q/W/E/R, làm nổi kỹ năng mạnh, hồi chiêu và tag chuẩn hóa.'))+libraryCoveragePanel('skills')+`<div class="library-layout skill-library-layout">${libraryList('skills',c.id)}${skillWorkbookPanel(c)}</div>`}

function finalSkillTags(record){return unique([...(record.tags||[]),...(record.ccTypes||[])]).slice(0,14)}
function finalSkillBadge(record){const rank=strongSkillRank(byId(record.championId)||state.focus&&byId(state.focus)||CHAMPIONS[0],record);return rank>=0?`<strong class="final-strong-badge">Strong #${rank+1}</strong>`:''}
function finalChampionHero(c,mode='champion'){const tags=[c.classification?.primary,c.classification?.secondary,c.damage?.type,c.damage?.profile,c.range,c.combat?.primary,c.combat?.macro].filter(Boolean),records=dedupedSkillRecords(c),main=kitRecords(c),high=records.filter(record=>record.impact==='High').length,cooldowns=records.filter(record=>String(record.cooldown||'').trim()).length;return `<section class="final-champion-hero"><div class="final-splash">${hoverChampion(c,'lg',c.primaryRole)}<span>${c.tier?esc(c.tier):'—'}</span></div><div class="final-hero-copy"><small>${esc(c.roles.join(' / '))} · ${esc(c.classification?.primary||'Champion')}</small><h2>${esc(c.name)}</h2><p>${esc([c.classification?.secondary,c.damage?.profile,c.combat?.primary,c.combat?.macro].filter(Boolean).join(' · ')||'Normalized champion profile')}</p><div class="final-hero-tags">${tags.map(tag=>`<span>${termIcon(tag)}<b>${esc(tag)}</b></span>`).join('')}</div></div><aside><span><small>Main kit</small><b>${main.length}/5</b></span><span><small>Skill records</small><b>${records.length}</b></span><span><small>High impact</small><b>${high}</b></span><span><small>Cooldown rows</small><b>${cooldowns}</b></span></aside></section>`}
function finalRatingPanel(c){const ratings=c.ratings||{},items=[['Attack','damage','Physical'],['Defense','toughness','Tank'],['Control','control','Vision'],['Mobility','mobility','Mobility'],['Utility','utility','Support']];return `<section class="final-card final-rating-panel"><div class="section-head"><h3>Core ratings</h3><span>5 core axes · difficulty is separate</span></div><div class="final-rating-grid">${items.map(([label,key,icon])=>{const value=Math.max(0,Math.min(5,Number(ratings[key])||0));return `<article><i>${filterIcon('className',icon)}</i><span><small>${esc(label)}</small><b>${value.toFixed(1)}</b></span><em><strong style="width:${value/5*100}%"></strong></em></article>`}).join('')}</div><div class="final-difficulty"><span>${filterIcon('className','Specialist')}<small>Difficulty</small><b>${esc(c.difficulty??'—')}</b></span><p>Difficulty is kept outside the combat rating so the profile stays readable.</p></div></section>`}
function finalProfileFacts(c){const stats=Object.entries(c.baseStats||{}).filter(([,v])=>v!=null).slice(0,12);return `<section class="final-card final-facts"><div class="section-head"><h3>Champion facts</h3><span>Champion!A1:DM204 + Riot normalized stats</span></div><div>${[['Patch',c.metadata?.patch],['Release year',c.metadata?.releaseYear],['Roles',c.roles.join(' / ')],['Range',c.range],['Damage type',c.damage?.type],['Attack style',attackStyle(c)]].map(([label,value])=>`<span><small>${esc(label)}</small><b>${esc(value||'—')}</b></span>`).join('')}</div>${stats.length?`<details><summary>Base stats</summary><div class="final-stat-grid">${stats.map(([key,value])=>`<span><small>${esc(key)}</small><b>${esc(value)}</b></span>`).join('')}</div></details>`:''}</section>`}
function finalSkillCard(record,c,mode='large'){const normalized=normalizedAbility(c,record),rank=strongSkillRank(c,normalized),strong=rank>=0,tags=finalSkillTags(normalized),image=normalized.images?.[0],detailRows=typeof skillDetailRows==='function'?skillDetailRows(normalized):'',summary=typeof skillSummary==='function'?skillSummary(normalized):'',effects=typeof skillEffectBurn==='function'?skillEffectBurn(normalized):'',forms=[...(normalized.forms||[])].filter(Boolean);return `<article class="final-skill-card ${mode} slot-${slug(normalized.slot)} ${strong?'is-strong':''} ${normalized.impact==='High'?'high-impact':normalized.impact==='Medium'?'mid-impact':''}" data-hover-skill="${esc(`${c?.id||normalized.championId||''}:${normalized.id||normalized.name}`)}"><header><span class="final-skill-slot">${esc(normalized.slot||'?')}</span>${image?`<img src="${esc(image)}" alt="${esc(normalized.name)}" width="64" height="64" loading="lazy" decoding="async">`:`<i>${esc((normalized.slot||'?')[0])}</i>`}<div><small>${esc(normalized.impact||'Standard')} impact${forms.length?` · ${forms.map(esc).join(' / ')}`:''}</small><h3>${esc(normalized.name||'Unknown skill')}</h3><em>${esc(normalized.cooldown||normalized.details?.cooldown||'No cooldown data')}</em></div>${strong?`<strong class="final-strong-badge">Strong #${rank+1}</strong>`:''}</header>${summary}<div class="final-skill-meta">${detailRows||`<span><small>Cooldown</small><b>${esc(normalized.cooldown||'—')}</b></span>`}<span><small>CC</small><b>${normalized.ccTypes?.length?normalized.ccTypes.map(esc).join(' / '):'—'}</b></span><span><small>Tags</small><b>${tags.length}</b></span></div>${effects}<footer>${tags.map(tag=>pill(tag,semanticTone(tag))).join('')||'<span class="muted">No tags</span>'}</footer></article>`}
function finalAbilityKit(c){const records=kitRecords(c),passive=records.find(record=>record.slot==='Passive'),main=primarySkillRecords(c);return `<section class="final-card final-ability-kit"><div class="section-head"><h3>Ability kit</h3><span>Passive + Q / W / E / R first · no duplicate main skills</span></div><div class="final-kit-strip">${records.map(record=>`<span class="${strongSkillRank(c,record)>=0?'active':''}">${record.images?.[0]?`<img src="${esc(record.images[0])}" alt="${esc(record.name)}">`:`<i>${esc(record.slot)}</i>`}<b>${esc(record.slot)}</b><small>${esc(record.cooldown||'—')}</small></span>`).join('')}</div>${passive?`<div class="final-passive">${finalSkillCard(passive,c,'passive')}</div>`:''}<div class="final-main-skills">${main.map(record=>finalSkillCard(record,c)).join('')}</div>${finalExtraForms(c)}</section>`}
function finalExtraForms(c){const mainKeys=new Set(kitRecords(c).map(record=>`${slug(record.slot)}:${slug(record.name)}`)),extra=dedupedSkillRecords(c).filter(record=>!mainKeys.has(`${slug(record.slot)}:${slug(record.name)}`));return extra.length?`<section class="final-extra-forms"><div class="section-head"><h3>Extra forms / alternate records</h3><span>Kept below the main kit to avoid clutter</span></div><div>${extra.map(record=>finalSkillCard(record,c,'compact')).join('')}</div></section>`:''}
function finalTagTaxonomy(c){const records=dedupedSkillRecords(c),groups=[['Damage',['Damage','Burst','DPS','AoE','Aoe','Poke','Execute','True Damage','Magic','Physical']],['Control',['CC','CC Hard','Airborne','Stun','Root','Slow','Silence','Fear','Charm','Suppress','Knockup','Displacement']],['Mobility',['Dash','Blink','Speed','Mobility']],['Defense',['Shield','Heal','Buff','Cleanse','Untargetable']],['Macro',['Clearwave','TeamFight','Engage','Disengage','Catch','Vision','Strong Ult']]],all=unique([...records.flatMap(r=>r.tags||[]),...(c.capabilities||[])]);return `<section class="final-card final-tag-taxonomy"><div class="section-head"><h3>Tag taxonomy</h3><span>Grouped from Skill!A1:BL211 and champion capability fields</span></div><div>${groups.map(([name,keys])=>{const tags=all.filter(tag=>keys.some(key=>semanticTagMatch(tag,key)));return `<article><b>${filterIcon('combat',name)}${esc(name)}</b><p>${tags.length?tags.map(tag=>pill(tag,semanticTone(tag))).join(''):'<span class="muted">No tags</span>'}</p></article>`}).join('')}</div></section>`}
function finalNotes(c){const guide=guideFor(c),empty='No data available.';return `<section class="final-card final-notes"><div class="section-head"><h3>Gameplan & spikes</h3><span>Readable tactical notes</span></div><div class="final-strengths"><article><b>Strengths</b><p>${esc(guide.strengths||empty)}</p></article><article><b>Weaknesses</b><p>${esc(guide.weaknesses||empty)}</p></article></div><div class="final-phase-notes">${PHASES.map(phase=>`<article><header><b>${esc(phase)}</b><span>${esc(c.power?.[phase]||'—')}</span></header><p>${esc(guide.gamePlan?.[phase]||empty)}</p><small>${esc(guide.powerSpikes?.[phase]||empty)}</small></article>`).join('')}</div></section>`}
function finalChampionPage(kind='champions'){const c=byId(state.focus)||CHAMPIONS[0];return pageIntro(kind==='skills'?'Skill library':'Champion library',kind==='skills'?'Visual champion kit: Passive + Q/W/E/R, strong-skill order, tags, cooldowns and alternate forms.':'Visual champion dashboard: identity, 5 core ratings, ability kit, tag taxonomy and tactical notes.')+`<div class="final-library-layout">${libraryList(kind,c.id)}<main class="final-champion-page ${kind==='skills'?'skill-mode':'champion-mode'}">${finalChampionHero(c,kind)}${kind==='skills'?`${finalAbilityKit(c)}${finalTagTaxonomy(c)}${finalRatingPanel(c)}`:`${finalRatingPanel(c)}${finalAbilityKit(c)}${finalTagTaxonomy(c)}${finalNotes(c)}${finalProfileFacts(c)}`}</main></div>`}
renderChampions=function(){return finalChampionPage('champions')}
renderSkills=function(){return finalChampionPage('skills')}
renderChampionsFull=function(){return renderChampions()}
renderSkillsFull=function(){return renderSkills()}

function itemText(item){return esc(String(item?.plaintext||item?.description||'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim()||'No item note')}
function statNumber(item,key){return Number(item?.stats?.[key])||0}
function itemTags(item){return Array.isArray(item?.tags)?item.tags:[]}
function itemTagText(item){return itemTags(item).join(' ').toLowerCase()}
function isPurchasableItem(item){return item&&item.gold?.purchasable&&item.inStore!==false&&!item.hideFromAll&&!item.consumed&&!item.consumeOnFull}
function completedItems(){return ITEMS.filter(item=>isPurchasableItem(item)&&!item.into?.length&&(Number(item.gold?.total)||0)>=1800)}
function starterItems(c){const wantsAp=/magic|mage|spell|ability/i.test(`${c.damage?.type} ${c.damage?.profile} ${c.classification?.primary}`),wantsAd=/physical|marksman|slayer|fighter/i.test(`${c.damage?.type} ${c.damage?.profile} ${c.classification?.primary}`),wantsTank=/tank|vanguard|warden|juggernaut/i.test(`${c.classification?.primary} ${c.classification?.secondary}`),ids=wantsAp?['1056','2003','1082']:wantsAd?['1055','2003','1083']:wantsTank?['1054','2003','1055']:['1055','2003','1054'];return ids.map(id=>ITEMS.find(item=>item.id===id)).filter(Boolean)}
function bootItems(c){const boots=ITEMS.filter(item=>isPurchasableItem(item)&&itemTags(item).includes('Boots')&&(Number(item.gold?.total)||0)>=900),ap=/magic|mage|spell/i.test(`${c.damage?.type} ${c.damage?.profile} ${c.classification?.primary}`),auto=attackStyle(c)==='Basic attack' || c.classification?.primary==='Marksman',tank=/tank|vanguard|warden|juggernaut/i.test(`${c.classification?.primary} ${c.classification?.secondary}`);return boots.map(item=>({item,score:(ap&&/sorcerer|ionian|lucidity/i.test(item.name)?10:0)+(auto&&/berserker/i.test(item.name)?12:0)+(tank&&/plated|mercury|steelcaps|merc/i.test(item.name)?10:0)+(Number(item.gold?.total)||0)/1000})).sort((a,b)=>b.score-a.score).slice(0,3).map(x=>x.item)}
function itemScore(item,c,style='recommended'){
  const text=`${item.name} ${itemTagText(item)} ${item.plaintext||''}`.toLowerCase();
  const ap=/magic|mage|spell|ap/i.test(`${c.damage?.type} ${c.damage?.profile} ${c.classification?.primary}`);
  const ad=/physical|marksman|slayer|fighter|ad/i.test(`${c.damage?.type} ${c.damage?.profile} ${c.classification?.primary}`);
  const auto=attackStyle(c)==='Basic attack'||/marksman|on-hit|dps/i.test(`${c.classification?.primary} ${c.damage?.profile}`);
  const tank=/tank|vanguard|warden|juggernaut|frontline/i.test(`${c.classification?.primary} ${c.classification?.secondary} ${c.combat?.positioning?.join(' ')}`);
  const support=/support|controller|enchanter|warden|utility/i.test(`${c.primaryRole} ${c.classification?.primary} ${c.classification?.secondary} ${c.combat?.secondary}`);
  let score=0;
  score+=statNumber(item,'FlatPhysicalDamageMod')*(ad?1.8:.45);
  score+=statNumber(item,'FlatMagicDamageMod')*(ap?1.8:.5);
  score+=statNumber(item,'PercentAttackSpeedMod')*(auto?160:45);
  score+=statNumber(item,'FlatCritChanceMod')*(auto?160:45);
  score+=statNumber(item,'PercentLifeStealMod')*(auto||ad?90:35);
  score+=statNumber(item,'FlatHPPoolMod')*(tank ? .45 : .14);
  score+=statNumber(item,'FlatArmorMod')*(tank?1.6:.45);
  score+=statNumber(item,'FlatSpellBlockMod')*(tank?1.55:.45);
  score+=statNumber(item,'FlatMPPoolMod')*(ap ? .08 : .03);
  if(text.includes('abilityhaste')||text.includes('cooldown'))score+=ap||support||tank?18:7;
  if(text.includes('armorpenetration')||text.includes('lethality'))score+=ad?24:4;
  if(text.includes('magicpenetration'))score+=ap?24:4;
  if(text.includes('onhit'))score+=auto?30:8;
  if(text.includes('criticalstrike'))score+=auto?28:6;
  if(text.includes('heal')||text.includes('shield'))score+=support?32:8;
  if(text.includes('active'))score+=style==='utility'||support?10:4;
  if(style==='damage')score+=statNumber(item,'FlatPhysicalDamageMod')+statNumber(item,'FlatMagicDamageMod')+statNumber(item,'FlatCritChanceMod')*120;
  if(style==='survive')score+=statNumber(item,'FlatHPPoolMod')*.35+statNumber(item,'FlatArmorMod')*2+statNumber(item,'FlatSpellBlockMod')*2;
  if(style==='utility')score+=(text.includes('heal')||text.includes('shield')||text.includes('active')||text.includes('slow')?35:0);
  if(style==='snowball')score+=(text.includes('kill')||text.includes('execute')||text.includes('takedown')||text.includes('penetration')?28:0);
  score+=(Number(item.gold?.total)||0)/1200;
  return score
}
function rankedItems(c,style='recommended',limit=9){return completedItems().filter(item=>!itemTags(item).includes('Boots')).map(item=>({item,score:itemScore(item,c,style)})).filter(x=>x.score>8).sort((a,b)=>b.score-a.score||String(a.item.name).localeCompare(b.item.name)).slice(0,limit).map(x=>x.item)}
function buildRecommendation(c,style='recommended'){const pool=rankedItems(c,style,10),core=pool.slice(0,3),situational=pool.slice(3,9);return {starter:starterItems(c),boots:bootItems(c),core,situational,style}}
function itemChip(item,rank=''){return `<span class="build-item-chip" title="${itemText(item)}">${item?.image?`<img src="${esc(item.image)}" alt="${esc(item.name)}">`:`<i>${esc((item?.name||'?')[0])}</i>`}<b>${rank?`<em>${esc(rank)}</em>`:''}${esc(item?.name||'Unknown item')}</b><small>${esc(item?.gold?.total?`${item.gold.total}g`:'—')}</small></span>`}
function buildStyleCards(c){const styles=[['recommended','Recommended','Best local fit from champion profile'],['damage','Damage','Maximize AD/AP, pen, crit or on-hit'],['survive','Survive','Health, armor, MR and anti-burst'],['utility','Utility','Actives, haste, heal/shield and setup'],['snowball','Snowball','Execute, burst and takedown tempo']];return `<section class="build-section build-styles"><div class="section-head"><h3>Item builds</h3><span>${esc(ITEM_DATA.patch||DATA.patch)} · Summoner's Rift items · local scoring</span></div><div class="build-style-grid">${styles.map(([id,label,copy])=>{const build=buildRecommendation(c,id);return `<article class="build-style-card style-${id}"><header><span>${termIcon(label)}</span><div><small>${esc(copy)}</small><h3>${esc(label)}</h3></div></header><div class="build-row"><b>Starter</b><p>${build.starter.map(item=>itemChip(item)).join('')}</p></div><div class="build-row core"><b>Core order</b><p>${build.core.map((item,index)=>itemChip(item,index+1)).join('')||'<span class="empty">No local item match</span>'}</p></div><div class="build-row"><b>Boots</b><p>${build.boots.map(item=>itemChip(item)).join('')}</p></div><div class="build-row"><b>Situational</b><p>${build.situational.map(item=>itemChip(item)).join('')}</p></div></article>`}).join('')}</div></section>`}
function buildOpponentFlags(opponent){const profile=`${opponent.damage?.type} ${opponent.damage?.profile} ${opponent.classification?.primary} ${opponent.classification?.secondary} ${opponent.combat?.primary} ${opponent.combat?.secondary}`.toLowerCase(),capabilities=(opponent.capabilities||[]).join(' ').toLowerCase(),magic=/magic|ap|mage/.test(profile),physical=/physical|ad|marksman|fighter|slayer/.test(profile),hybrid=/hybrid|mixed|true/.test(profile)||(magic&&physical);return {magic,physical,hybrid,tank:/tank|warden|vanguard|juggernaut|frontline/.test(profile),burst:/burst|assassin|slayer|execute/.test(`${profile} ${capabilities}`),sustain:/heal|lifesteal|omnivamp|sustain|regeneration/.test(capabilities),shield:/shield/.test(capabilities),cc:/stun|root|airborne|fear|charm|suppress|silence|cc hard/.test(capabilities),auto:attackStyle(opponent)==='Basic attack'||/marksman|on-hit|dps/.test(profile)}}
function matchupItemText(item){return `${item.name} ${itemTagText(item)} ${item.plaintext||''} ${item.description||''}`.replace(/<[^>]+>/g,' ').toLowerCase()}
function matchupItemScore(item,c,opponent){const flags=buildOpponentFlags(opponent),text=matchupItemText(item),armor=statNumber(item,'FlatArmorMod'),mr=statNumber(item,'FlatSpellBlockMod'),hp=statNumber(item,'FlatHPPoolMod');let score=itemScore(item,c,'recommended');if(flags.hybrid)score+=armor*1.8+mr*1.8+hp*.16;else if(flags.magic)score+=mr*4+hp*.08;else if(flags.physical)score+=armor*4+hp*.08;if(flags.burst)score+=armor*1.1+mr*1.1+hp*.14;if(flags.tank&&/armorpenetration|magicpenetration|percent.*health|maximum health|bonus health|onhit/.test(text))score+=54;if(flags.sustain&&/grievous wounds/.test(text))score+=70;if(flags.shield&&/shield reaver|serpent/.test(text))score+=60;return score}
function matchupItemReason(item,opponent){const flags=buildOpponentFlags(opponent),text=matchupItemText(item),reasons=[];if(flags.physical&&statNumber(item,'FlatArmorMod'))reasons.push('Armor vs physical');if(flags.magic&&statNumber(item,'FlatSpellBlockMod'))reasons.push('MR vs magic');if(flags.hybrid&&statNumber(item,'FlatHPPoolMod'))reasons.push('HP vs mixed damage');if(flags.burst&&statNumber(item,'FlatHPPoolMod'))reasons.push('Anti-burst');if(flags.tank&&/armorpenetration|magicpenetration|percent.*health|maximum health|bonus health|onhit/.test(text))reasons.push('Tank answer');if(flags.sustain&&/grievous wounds/.test(text))reasons.push('Anti-heal');if(flags.shield&&/shield reaver|serpent/.test(text))reasons.push('Anti-shield');return reasons.slice(0,2)}
function matchupBoots(c,opponent){const flags=buildOpponentFlags(opponent),boots=ITEMS.filter(item=>isPurchasableItem(item)&&itemTags(item).includes('Boots')&&(Number(item.gold?.total)||0)>=900);return boots.map(item=>{const name=item.name.toLowerCase();let score=itemScore(item,c,'recommended');if(flags.physical&&(flags.auto||flags.burst)&&/plated|steelcaps/.test(name))score+=120;if((flags.magic||flags.cc)&&/mercury/.test(name))score+=120;return {item,score}}).sort((a,b)=>b.score-a.score).slice(0,2).map(row=>row.item)}
function matchupBuild(c,opponent){const coreIds=new Set(buildRecommendation(c).core.map(item=>item.id)),items=completedItems().filter(item=>!itemTags(item).includes('Boots')&&!coreIds.has(item.id)).map(item=>({item,score:matchupItemScore(item,c,opponent)})).sort((a,b)=>b.score-a.score||String(a.item.name).localeCompare(String(b.item.name))).slice(0,4).map(row=>row.item);return {items,boots:matchupBoots(c,opponent)}}
function matchupBuildPanel(c){const opponent=byId(state.buildOpponent),options=CHAMPIONS.filter(champion=>champion.id!==c.id).sort((a,b)=>a.name.localeCompare(b.name));if(!opponent)return `<section class="build-matchup-panel empty-matchup"><div><span class="source-kicker">Matchup adaptation</span><h3>Build against a specific opponent</h3><p>Choose the lane opponent to prioritize the right defense, boots and situational answers. This is local logic, not a claimed KR win-rate.</p></div><label><span>Opponent</span><select data-build-opponent><option value="">Choose an opponent</option>${options.map(champion=>`<option value="${champion.id}">${esc(champion.name)}</option>`).join('')}</select></label></section>`;const result=matchupBuild(c,opponent),flags=buildOpponentFlags(opponent),threats=[flags.magic?'Magic':null,flags.physical?'Physical':null,flags.hybrid?'Mixed':null,flags.burst?'Burst':null,flags.tank?'Tank':null,flags.sustain?'Sustain':null,flags.cc?'Hard CC':null].filter(Boolean);return `<section class="build-matchup-panel"><header><div class="build-matchup-title">${portrait(c,'sm')}<span><small>Your champion</small><b>${esc(c.name)}</b></span><i>VS</i>${portrait(opponent,'sm')}<span><small>Opponent</small><b>${esc(opponent.name)}</b></span></div><label><span>Change opponent</span><select data-build-opponent><option value="">None</option>${options.map(champion=>`<option value="${champion.id}" ${champion.id===opponent.id?'selected':''}>${esc(champion.name)}</option>`).join('')}</select></label></header><div class="matchup-threat-tags">${threats.map(threat=>`<span class="threat-${slug(threat)}">${esc(threat)}</span>`).join('')}</div><div class="matchup-build-grid"><article><small>Adapt after core</small><div>${result.items.map((item,index)=>`<div>${itemChip(item,index+1)}<p>${matchupItemReason(item,opponent).map(reason=>`<span>${esc(reason)}</span>`).join('')||'<span>Champion-compatible option</span>'}</p></div>`).join('')}</div></article><article><small>Boot response</small><div>${result.boots.map(item=>`<div>${itemChip(item)}<p>${matchupItemReason(item,opponent).map(reason=>`<span>${esc(reason)}</span>`).join('')||'<span>Best local matchup fit</span>'}</p></div>`).join('')}</div></article></div><p class="matchup-disclaimer">Use the KR live source below to verify pick rate and sample size. Local adaptation only changes situational choices; it does not invent observed statistics.</p></section>`}
const SUMMONER_SPELLS={Flash:{file:'SummonerFlash.png',note:'Reposition, escape or commit to a decisive play.'},Teleport:{file:'SummonerTeleport.png',note:'Return to lane and preserve side-lane tempo.'},Smite:{file:'SummonerSmite.png',note:'Required for jungle clear and objective control.'},Ignite:{file:'SummonerDot.png',note:'Kill pressure and anti-heal for all-ins.'},Exhaust:{file:'SummonerExhaust.png',note:'Reduce an enemy carry or burst window.'},Heal:{file:'SummonerHeal.png',note:'Two-player sustain and movement speed.'},Barrier:{file:'SummonerBarrier.png',note:'Personal protection against focused burst.'},Cleanse:{file:'SummonerBoost.png',note:'Remove eligible crowd control and survive the follow-up.'},Ghost:{file:'SummonerHaste.png',note:'Extended mobility for chase and kite.'}};
function summonerSpellImage(name){const spell=SUMMONER_SPELLS[name],patch=ITEM_DATA.patch||DATA.patch;return `<img src="https://ddragon.leagueoflegends.com/cdn/${esc(patch)}/img/spell/${esc(spell.file)}" alt="${esc(name)}" width="48" height="48" loading="lazy" decoding="async">`}
function summonerSpellRecommendations(c){const opponent=byId(state.buildOpponent),flags=opponent?buildOpponentFlags(opponent):{},role=c.primaryRole;let pair=['Flash','Teleport'],why='Standard solo-lane setup for safety and map tempo.';if(role==='Jungle'){pair=['Smite','Flash'];why='Smite is mandatory for jungle economy and neutral objectives.'}else if(role==='AD'){pair=['Flash','Barrier'];why='Barrier protects the carry during the highest incoming burst.'}else if(role==='Support'){pair=['Flash','Ignite'];why='Ignite adds lane pressure and cuts enemy healing.'}if(opponent&&role!=='Jungle'){if(flags.cc&&['Mid','AD','Support'].includes(role)){pair=['Flash','Cleanse'];why=`Cleanse is prioritized into ${opponent.name}'s eligible hard crowd control.`}else if(flags.burst&&['AD','Support'].includes(role)){pair=['Flash','Exhaust'];why=`Exhaust reduces ${opponent.name}'s main burst window.`}else if(flags.sustain&&['Top','Mid','Support'].includes(role)){pair=['Flash','Ignite'];why=`Ignite limits ${opponent.name}'s sustain during the all-in.`}}const pool={Top:['Teleport','Ignite','Ghost'],Jungle:['Flash','Ghost'],Mid:['Teleport','Ignite','Barrier','Cleanse'],AD:['Barrier','Cleanse','Heal','Exhaust'],Support:['Ignite','Exhaust','Heal','Cleanse']}[role]||['Teleport','Ignite','Barrier'];return {pair,why,alternatives:pool.filter(name=>!pair.includes(name)).slice(0,3),opponent}}
function summonerSpellCard(name,label=''){const spell=SUMMONER_SPELLS[name];return `<article class="summoner-spell-card">${summonerSpellImage(name)}<span>${label?`<small>${esc(label)}</small>`:''}<b>${esc(name)}</b><em>${esc(spell.note)}</em></span></article>`}
function summonerSpellPanel(c){const setup=summonerSpellRecommendations(c);return `<section class="build-section summoner-panel"><div class="section-head"><h3>Summoner spells</h3><span>Official Riot images · local role${setup.opponent?' + matchup':''} logic</span></div><div class="summoner-layout"><article class="summoner-primary"><header><span>Recommended pair</span><b>${esc(setup.pair.join(' + '))}</b></header><div>${setup.pair.map((name,index)=>summonerSpellCard(name,index?'Second spell':'Core spell')).join('')}</div><p>${esc(setup.why)}</p></article><article class="summoner-alternatives"><header><span>Alternatives</span><small>Switch when the game plan changes</small></header><div>${setup.alternatives.map(name=>summonerSpellCard(name)).join('')}</div></article></div></section>`}
const RUNE_ICON_BASE='https://ddragon.leagueoflegends.com/cdn/img/';
const RUNE_ICON_PATHS={'Arcane Comet':'perk-images/Styles/Sorcery/ArcaneComet/ArcaneComet.png','Biscuit Delivery':'perk-images/Styles/Inspiration/BiscuitDelivery/BiscuitDelivery.png','Bone Plating':'perk-images/Styles/Resolve/BonePlating/BonePlating.png','Conqueror':'perk-images/Styles/Precision/Conqueror/Conqueror.png','Cosmic Insight':'perk-images/Styles/Inspiration/CosmicInsight/CosmicInsight.png','Coup de Grace':'perk-images/Styles/Precision/CoupDeGrace/CoupDeGrace.png','Demolish':'perk-images/Styles/Resolve/Demolish/Demolish.png','Domination':'perk-images/Styles/7200_Domination.png','Electrocute':'perk-images/Styles/Domination/Electrocute/Electrocute.png','Eyeball Collection':'perk-images/Styles/Domination/EyeballCollection/EyeballCollection.png','Glacial Augment':'perk-images/Styles/Inspiration/GlacialAugment/GlacialAugment.png','Grasp of the Undying':'perk-images/Styles/Resolve/GraspOfTheUndying/GraspOfTheUndying.png','Inspiration':'perk-images/Styles/7203_Whimsy.png','Last Stand':'perk-images/Styles/Sorcery/LastStand/LastStand.png','Legend: Alacrity':'perk-images/Styles/Precision/LegendAlacrity/LegendAlacrity.png','Legend: Haste':'perk-images/Styles/Precision/LegendHaste/LegendHaste.png','Magical Footwear':'perk-images/Styles/Inspiration/MagicalFootwear/MagicalFootwear.png','Manaflow Band':'perk-images/Styles/Sorcery/ManaflowBand/ManaflowBand.png','Overgrowth':'perk-images/Styles/Resolve/Overgrowth/Overgrowth.png','Precision':'perk-images/Styles/7201_Precision.png','Press the Attack':'perk-images/Styles/Precision/PressTheAttack/PressTheAttack.png','Resolve':'perk-images/Styles/7204_Resolve.png','Revitalize':'perk-images/Styles/Resolve/Revitalize/Revitalize.png','Scorch':'perk-images/Styles/Sorcery/Scorch/Scorch.png','Second Wind':'perk-images/Styles/Resolve/SecondWind/SecondWind.png','Sorcery':'perk-images/Styles/7202_Sorcery.png','Sudden Impact':'perk-images/Styles/Domination/SuddenImpact/SuddenImpact.png','Transcendence':'perk-images/Styles/Sorcery/Transcendence/Transcendence.png','Triumph':'perk-images/Styles/Precision/Triumph.png','Ultimate Hunter':'perk-images/Styles/Domination/UltimateHunter/UltimateHunter.png'};
function runeIcon(name,size='rune'){const path=RUNE_ICON_PATHS[name];return path?`<img class="${size}" src="${RUNE_ICON_BASE}${esc(path)}" alt="${esc(name)}" loading="lazy" decoding="async">`:`<i class="${size}">${esc(String(name||'?')[0])}</i>`}
function runePage(c){const text=`${c.primaryRole} ${c.classification?.primary} ${c.classification?.secondary} ${c.damage?.profile} ${c.combat?.primary} ${c.combat?.secondary}`.toLowerCase(),auto=attackStyle(c)==='Basic attack'||text.includes('marksman'),tank=/tank|vanguard|warden|juggernaut/.test(text),burst=/assassin|burst|slayer|catch/.test(text),support=/support|enchanter|controller|shield|heal/.test(text),mage=/mage|magic|poke|spell/.test(text);let primary=mage?['Sorcery','Arcane Comet','Manaflow Band','Transcendence','Scorch']:burst?['Domination','Electrocute','Sudden Impact','Eyeball Collection','Ultimate Hunter']:tank?['Resolve','Grasp of the Undying','Demolish','Second Wind','Overgrowth']:support?['Inspiration','Glacial Augment','Magical Footwear','Biscuit Delivery','Cosmic Insight']:auto?['Precision','Press the Attack','Triumph','Legend: Alacrity','Coup de Grace']:['Precision','Conqueror','Triumph','Legend: Haste','Last Stand'];const secondary=tank?['Precision','Triumph','Last Stand']:support?['Resolve','Bone Plating','Revitalize']:mage?['Inspiration','Biscuit Delivery','Cosmic Insight']:['Resolve','Bone Plating','Overgrowth'];return {primary,secondary,shards:['Adaptive Force','Move Speed / Adaptive','Scaling Health'],note:'Derived baseline from champion profile. Rune icons are loaded from Riot Data Dragon runesReforged assets for the current patch.'}}
function runePanel(c){const page=runePage(c),column=(title,runes,secondary=false)=>`<article><header>${runeIcon(title,'rune-style')}<b>${esc(title)}</b><small>${secondary?'Secondary path':'Primary path'}</small></header>${runes.map((rune,index)=>`<span class="${index===0&&!secondary?'keystone':''}">${runeIcon(rune)}<em>${esc(rune)}</em></span>`).join('')}${secondary?`<small class="rune-shards">${page.shards.map(esc).join(' · ')}</small>`:''}</article>`;return `<section class="build-section rune-panel"><div class="section-head"><h3>Rune page</h3><span>Riot Data Dragon icons · profile-derived baseline</span></div><div class="rune-columns">${column(page.primary[0],page.primary.slice(1))}${column(page.secondary[0],page.secondary.slice(1),true)}</div><p>${esc(page.note)}</p></section>`}
function skillOrder(c){const skills=primarySkillRecords(c).filter(record=>['Q','W','E'].includes(record.slot)),ranked=[...skills].sort((a,b)=>strongSkillRank(c,a)-strongSkillRank(c,b)),fallback=skills.sort((a,b)=>['Q','W','E'].indexOf(a.slot)-['Q','W','E'].indexOf(b.slot)),order=(ranked.length&&strongSkillRank(c,ranked[0])>=0?ranked:fallback).map(record=>record.slot),levels=[];for(let level=1;level<=18;level++){if([6,11,16].includes(level)){levels.push('R');continue}levels.push(order[(level-1)%Math.max(1,order.length)]||'Q')}return levels}
function levelUpPanel(c){const levels=skillOrder(c),records=Object.fromEntries(kitRecords(c).map(record=>[record.slot,record]));return `<section class="build-section level-panel"><div class="section-head"><h3>Level up</h3><span>Strong-skill order + R at 6 / 11 / 16</span></div><div class="level-grid">${levels.map((slot,index)=>{const record=records[slot];return `<span class="slot-${slug(slot)}"><small>${index+1}</small>${record?.images?.[0]?`<img src="${esc(record.images[0])}" alt="${esc(record.name)}">`:`<i>${esc(slot)}</i>`}<b>${esc(slot)}</b></span>`}).join('')}</div><div class="level-priority">${unique(levels.filter(slot=>slot!=='R')).slice(0,3).map((slot,index)=>{const record=records[slot];return `<span><b>${index+1}</b>${record?.images?.[0]?`<img src="${esc(record.images[0])}" alt="${esc(record.name)}">`:`<i>${esc(slot)}</i>`}<em>Max ${esc(slot)}</em><small>${esc(record?.name||'Skill')}</small></span>`}).join('')}</div></section>`}
function buildSourcePanel(c){const champion=slug(c.name),role={Top:'top',Jungle:'jungle',Mid:'mid',AD:'adc',Support:'support'}[c.primaryRole]||'top',patch=ITEM_DATA.patch||DATA.patch;return `<section class="build-source"><div class="build-source-head"><div><span class="source-kicker">Source contract</span><h3>What this page is actually using</h3></div><span class="source-patch">Patch ${esc(patch)} · Summoner's Rift</span></div><div class="source-contract-grid"><article><b>Riot Data Dragon</b><p>Official item stats, costs and images. It does not provide live best-build win rate.</p><span class="source-status verified">Official assets</span></article><article><b>Local profile engine</b><p>Current item order, rune baseline, skill order and opponent adaptation are deterministic app logic.</p><span class="source-status local">No fake sample</span></article><article><b>KR live reference</b><p>Open OP.GG with KR selected to verify current pick rate, win rate, core order and counters.</p><span class="source-status live">External live data</span></article></div><div class="build-source-links"><a href="https://op.gg/ko/lol/champions/${champion}/build?region=kr" target="_blank" rel="noreferrer">OP.GG KR build ↗</a><a href="https://op.gg/ko/lol/champions/${champion}/counters/${role}?region=kr" target="_blank" rel="noreferrer">OP.GG KR counters ↗</a><a href="https://www.leagueofgraphs.com/champions/builds/${champion}" target="_blank" rel="noreferrer">League of Graphs cross-check ↗</a></div></section>`}
function checkActiveFilterCount(){const f=state.finder;return (f.search?1:0)+(f.releaseYear?1:0)+Object.values(f.phase||{}).filter(Boolean).length+['roles','classes','skillClasses','combat','range','tiers','profiles','damageTypes','damageProfiles','positions','attackStyles','capabilities','skillEffects','counterTargets','matchupTargets'].reduce((sum,key)=>sum+(f[key]?.length||0),0)}
const renderCheckSelectorBase=renderCheckSelector;
renderCheckSelector=function(){const count=checkActiveFilterCount();return renderCheckSelectorBase().replace('<label class="check-search"><span>Search</span>','<button type="button" class="check-reset-button" data-action="clear-filters" '+(count?'':'disabled')+'>Reset filters'+(count?` · ${count}`:'')+'</button><label class="check-search"><span>Search</span>')}
checkSelectedRelationsPanel=function(c,lane){const relations=matchupsFor(c,lane),groups=[['Counter',relations.counters,'danger','Counters'],['Good lane',relations.bestLane,'lane','Lane edge'],['Duo',relations.synergies,'success','Works with'],['Ban',relations.bans,'warning','Ban target']];const card=(name,tone,index,label)=>{const champion=splitName(name);return `<button type="button" class="check-relation-card ${tone}" ${champion?`data-focus="${champion.id}"`:''} title="${esc(name)}">${portrait(champion||name,'xs')}<span><b>${esc(champion?.name||name)}</b><small>${esc(champion?.primaryRole||label)} · #${index+1}</small></span>${checkRelationIcon(tone)}</button>`};return `<section class="check-selected-relations check-relation-cards" aria-label="${esc(c.name)} relations"><header><b>${esc(c.name)}</b><span>${esc(lane)} matchup board</span></header><div>${groups.map(([title,names,tone,label])=>{const list=unique((names||[]).filter(Boolean)).slice(0,8);return `<article class="${tone}"><h4>${checkRelationIcon(tone)}<span>${esc(title)}</span><b>${names?.length||0}</b></h4><div>${list.map((name,index)=>card(name,tone,index,label)).join('')||'<em>—</em>'}</div></article>`}).join('')}</div></section>`}
function checkSearchHaystack(c){return slug([c.name,c.id,...(c.roles||[]),c.primaryRole,c.range,c.tier,...Object.values(c.classification||{}),...Object.values(c.damage||{}),...Object.values(c.combat||{}).flat(),...(c.capabilities||[]),...(c.skillTags||[]),...(c.abilities||[]).flatMap(a=>[a.name,a.slot,...(a.tags||[]),...(a.ccTypes||[])])].flat().filter(Boolean).join(' '))}
finderPass=function(c){const f=state.finder,group=(selected,values=[])=>!selected.length||selected.some(x=>values.includes(x)),profiles=Object.entries(c.profiles||{}).filter(([,v])=>v).map(([k])=>k),capabilities=(c.capabilities||[]).map(slug),skillEffects=(c.skillTags||(c.abilities||[]).flatMap(ability=>ability.tags||[])).map(slug),needle=slug(f.search||'');return (!needle||checkSearchHaystack(c).includes(needle))&&group(f.roles,c.roles)&&group(f.classes,Object.values(c.classification||{}))&&group(f.skillClasses,championSkillClasses(c))&&group(f.combat,[c.combat?.primary,c.combat?.secondary,c.combat?.macro].filter(Boolean))&&group(f.range,[c.range])&&group(f.tiers,[c.tier])&&group(f.profiles,profiles)&&group(f.damageTypes,[c.damage?.type])&&group(f.damageProfiles,[c.damage?.profile])&&group(f.positions,c.combat?.positioning||[])&&group(f.attackStyles,[attackStyle(c)])&&(!f.releaseYear||championReleaseYear(c)===String(f.releaseYear))&&f.capabilities.every(x=>capabilities.includes(slug(x)))&&group(f.skillEffects.map(slug),skillEffects)&&f.counterTargets.every(target=>countersTarget(c,target))&&f.matchupTargets.every(target=>matchupFitsTarget(c,target))&&Object.entries(f.phase).every(([p,v])=>!v||c.power?.[p]===v)}
function checkSearchSuggestions(pool,skillEffects){const values=unique([...pool.map(c=>c.name),...pool.flatMap(c=>(c.abilities||[]).map(a=>a.name)),...skillEffects]).filter(Boolean).slice(0,360);return `<datalist id="check-search-suggestions">${values.map(value=>`<option value="${esc(value)}"></option>`).join('')}</datalist>`}
function checkSkillEffectToggles(skillEffects){const selected=state.finder.skillEffects||[],priority=['Engage','Disengage','Poke','Catch','Dive','CC','CC Hard','CC Chain','Airborne','Stun','Root','Slow','Mobility','Dash','Blink','Heal','Shield','Clearwave','Vision','Strong Ult','TeamFight','Burst','Dps','Aoe','Reset','Global','Buff','Peel','Sustain'],counts=new Map();CHAMPIONS.forEach(c=>(c.skillTags||[]).forEach(tag=>counts.set(tag,(counts.get(tag)||0)+1)));const top=unique([...priority,...skillEffects.sort((a,b)=>(counts.get(b)||0)-(counts.get(a)||0)||a.localeCompare(b))]).filter(value=>skillEffects.includes(value)).slice(0,48);return `<details class="check-multi-filter check-skill-effect-or" ${selected.length?'open':''}><summary><span>Skill tags / effects</span><b><i>${selected.length||'Any'}</i><em>OR</em></b></summary><div>${top.map(value=>checkFilterToggle('skillEffects',value,value,'')).join('')}</div><label><span>Add exact tag</span><select data-check-effect-add><option value="">Choose tag...</option>${skillEffects.filter(value=>!selected.includes(value)).map(value=>`<option value="${esc(value)}">${esc(value)}</option>`).join('')}</select></label></details>`}
checkSelectedRelationsPanel=function(c,lane){const relations=matchupsFor(c,lane),groups=[['Counter',relations.counters,'danger','Counters'],['Ban',relations.bans,'warning','Ban target'],['Lane',relations.bestLane,'lane','Lane edge'],['Duo',relations.synergies,'success','Works with']];const card=(name,tone,index,label)=>{const champion=splitName(name);return `<button type="button" class="check-relation-card ${tone}" ${champion?`data-focus="${champion.id}"`:''} title="${esc(name)}">${portrait(champion||name,'xs')}<span><b>${esc(champion?.name||name)}</b><small>${esc(champion?.primaryRole||label)} · #${index+1}</small></span>${checkRelationIcon(tone)}</button>`};return `<section class="check-selected-relations check-relation-cards" aria-label="${esc(c.name)} relations"><header><b>${esc(c.name)}</b><span>${esc(lane)} matchup board</span></header><div>${groups.map(([title,names,tone,label])=>{const list=unique((names||[]).filter(Boolean)).slice(0,8);return `<article class="${tone}"><h4>${checkRelationIcon(tone)}<span>${esc(title)}</span><b>${names?.length||0}</b></h4><div>${list.map((name,index)=>card(name,tone,index,label)).join('')||'<em>—</em>'}</div></article>`}).join('')}</div></section>`}
renderCheckSelector=function(){const count=checkActiveFilterCount(),pool=checkChampionPool(),matches=pool.filter(finderPass),selected=canonicalChampion(byId(state.focus))||matches[0]||pool[0]||CHAMPIONS[0],selectedLane=state.finder.roles[0]||normalizedLane(state.checkLane)||normalizedLane(selected.primaryRole),years=unique(pool.map(championReleaseYear)).filter(Boolean).sort((a,b)=>Number(b)-Number(a)),classes=unique(pool.flatMap(c=>[c.classification.primary,c.classification.secondary])).filter(Boolean).sort(),damageProfiles=unique(pool.map(c=>c.damage.profile)).filter(Boolean).sort(),damageTypes=unique(pool.map(c=>c.damage.type)).filter(Boolean).sort(),positions=unique(pool.flatMap(c=>c.combat.positioning)).filter(Boolean).sort(),skillClasses=unique(pool.flatMap(championSkillClasses)).filter(Boolean).sort(),skillEffects=unique(pool.flatMap(c=>c.skillTags||[])).filter(Boolean).sort((a,b)=>a.localeCompare(b)),roleCodes={Top:'T',Jungle:'J',Mid:'M',AD:'A',Support:'S'},classCodes={Fighter:'FI',Mage:'MG',Marksman:'MM',Slayer:'SL',Tank:'TK',Controller:'CT',Specialist:'SP'},combat=unique(pool.flatMap(c=>[c.combat.primary,c.combat.secondary,c.combat.macro])).filter(Boolean).sort(),features=checkFeatureOptions();return `<section class="check-selector check-one-screen">${checkSearchSuggestions(pool,skillEffects)}<div class="check-topbar check-topbar-compact"><label class="check-year"><span>Year</span><select data-year-filter><option value="">Any</option>${years.map(year=>`<option value="${year}" ${state.finder.releaseYear===year?'selected':''}>${year}</option>`).join('')}</select></label><div class="check-icon-group"><span>Lane</span><div>${ROLES.map(role=>`<button type="button" data-check-role="${role}" class="${state.finder.roles.includes(role)?'active':''}" aria-pressed="${state.finder.roles.includes(role)}"><b class="check-lane-icon">${filterIcon('role',role)}</b><em>${roleCodes[role]}</em><small data-no-translate>${role}</small></button>`).join('')}</div></div><button type="button" class="check-reset-button" data-action="clear-filters" ${count?'':'disabled'}>Reset filters${count?` · ${count}`:''}</button><label class="check-search"><span>Search</span><input data-finder-search list="check-search-suggestions" value="${esc(state.finder.search)}" placeholder="Champion, skill, tag..."></label></div><div class="check-body"><aside class="check-name-rail"><header><b>${matches.length}</b><span>match</span></header><div>${matches.map(c=>`<button type="button" data-focus="${c.id}" class="${c.id===selected.id?'active':''}" aria-pressed="${c.id===selected.id}" title="${esc(c.name)}"><span>${esc(c.name)}</span></button>`).join('')||'<p>No match</p>'}</div></aside><main class="check-center"><div class="check-champion-grid" style="--check-columns:18">${pool.map(c=>{const available=finderPass(c),isSelected=c.id===selected.id,label=`${c.name} · ${c.primaryRole} · ${c.classification.primary}`;return `<button type="button" data-focus="${c.id}" class="${available?'available':'dimmed'} ${isSelected?'selected':''}" aria-label="${esc(label)}" aria-pressed="${isSelected}" title="${esc(label)}">${portrait(c,'xs')}<span class="check-champ-label"><b>${esc(c.name)}</b><small data-no-translate>${esc(c.primaryRole)}</small></span><i class="check-champ-icons" aria-hidden="true">${filterIcon('role',c.primaryRole)}${filterIcon('className',c.classification.primary)}</i></button>`}).join('')}</div>${checkSelectedRelationsPanel(selected,selectedLane)}</main><aside class="check-filter-console"><section class="check-selected-preview">${portrait(selected,'lg')}<div><small>${esc(selectedLane)} · ${esc(selected.tier||'No grade')}</small><h3>${esc(selected.name)}</h3><p>${esc(selected.roles.join(' · '))} · ${esc(selected.damage.profile)}</p><div>${selected.capabilities.slice(0,4).map(value=>pill(value)).join('')}</div></div></section><div class="check-phase-row">${PHASES.map(phase=>`<label><span>${phase}</span><select data-phase-filter="${phase}"><option value="">Any</option>${DATA.dictionary.power.map(value=>`<option value="${esc(value)}" ${state.finder.phase[phase]===value?'selected':''}>${esc(value)}</option>`).join('')}</select></label>`).join('')}</div><div class="check-dropdown-grid check-single-grid">${checkSelect('damageProfiles','Style damage',damageProfiles)}${checkSelect('damageTypes','Type damage',damageTypes)}${checkSelect('range','Range type',['Melee','Ranged'])}${checkSelect('skillClasses','Skill class',skillClasses)}</div>${checkMultiFilter('classes','Class',Object.entries(classCodes),{mode:'OR',open:true})}${checkMultiFilter('positions','Position',positions.map(value=>[value,{Frontline:'F',Midline:'M',Backline:'B',Flank:'FL'}[value]||'']),{mode:'OR',open:true})}<section class="check-icon-row check-attack-style"><header><span>Skill type</span><b>${state.finder.attackStyles.length||'Any'}</b></header><div>${[['Ability','AP'],['Hybrid','HY'],['Basic attack','AA']].map(([value,code])=>checkFilterToggle('attackStyles',value,value,code)).join('')}</div></section>${checkMultiFilter('combat','Combat',combat,{mode:'OR'})}${checkMultiFilter('capabilities','Skill features',features,{mode:'AND'})}${checkSkillEffectToggles(skillEffects)}<section class="check-icon-row check-positive-row"><header><span>Positive</span><b>${state.finder.profiles.length||'Any'}</b></header><div>${[['mastery','Master'],['carry','Carry'],['hyperCarry','Hyper Carry'],['flex','Flex']].map(([value,label])=>checkFilterToggle('profiles',value,label,{mastery:'M',carry:'C',hyperCarry:'HC',flex:'F'}[value])).join('')}</div></section><div class="check-grade check-grade-compact"><span>Meta grade</span>${['S+','S','A+','A'].map(value=>checkFilterToggle('tiers',value,value,value)).join('')}</div></aside></div></section>`}
buildStyleCards=function(c){const styles=[['recommended','Core','Best fit'],['survive','Defensive','Safer'],['snowball','Snowball','Lead']];return `<section class="build-section build-styles build-styles-compact"><div class="section-head"><h3>Items</h3><span>Patch ${esc(ITEM_DATA.patch||DATA.patch)}</span></div><div class="build-style-grid">${styles.map(([id,label,copy])=>{const build=buildRecommendation(c,id);return `<article class="build-style-card style-${id}"><header><span>${termIcon(label)}</span><div><small>${esc(copy)}</small><h3>${esc(label)}</h3></div></header><div class="build-row core"><b>Core</b><p>${build.core.map((item,index)=>itemChip(item,index+1)).join('')||'<span class="empty">No item match</span>'}</p></div><div class="build-row"><b>Start</b><p>${build.starter.map(item=>itemChip(item)).join('')}</p></div><div class="build-row"><b>Boots</b><p>${build.boots.slice(0,2).map(item=>itemChip(item)).join('')}</p></div><div class="build-row"><b>Flex</b><p>${build.situational.slice(0,4).map(item=>itemChip(item)).join('')}</p></div></article>`}).join('')}</div></section>`}
matchupBuildPanel=function(c){const opponent=byId(state.buildOpponent),options=CHAMPIONS.filter(champion=>champion.id!==c.id).sort((a,b)=>a.name.localeCompare(b.name));if(!opponent)return `<section class="build-matchup-panel build-matchup-compact empty-matchup"><div><span class="source-kicker">Matchup</span><h3>Pick opponent</h3></div><label><span>Opponent</span><select data-build-opponent><option value="">None</option>${options.map(champion=>`<option value="${champion.id}">${esc(champion.name)}</option>`).join('')}</select></label></section>`;const result=matchupBuild(c,opponent),flags=buildOpponentFlags(opponent),threats=[flags.magic?'Magic damage':null,flags.physical?'Physical damage':null,flags.hybrid?'Mixed damage':null,flags.burst?'Burst':null,flags.tank?'Tank':null,flags.sustain?'Sustain':null,flags.cc?'Control':null].filter(Boolean);return `<section class="build-matchup-panel build-matchup-compact"><header><div class="build-matchup-title">${portrait(c,'sm')}<span><small>You</small><b>${esc(c.name)}</b></span><i>VS</i>${portrait(opponent,'sm')}<span><small>Opponent</small><b>${esc(opponent.name)}</b></span></div><label><span>Opponent</span><select data-build-opponent><option value="">None</option>${options.map(champion=>`<option value="${champion.id}" ${champion.id===opponent.id?'selected':''}>${esc(champion.name)}</option>`).join('')}</select></label></header><div class="matchup-threat-tags">${threats.map(threat=>`<span class="threat-${slug(threat)}">${esc(threat)}</span>`).join('')}</div><div class="matchup-build-grid"><article><small>Adapt</small><div>${result.items.slice(0,3).map((item,index)=>`<div>${itemChip(item,index+1)}<p>${matchupItemReason(item,opponent).map(reason=>`<span>${esc(reason.replace('MR','Magic resist'))}</span>`).join('')||'<span>Good fit</span>'}</p></div>`).join('')}</div></article><article><small>Boots</small><div>${result.boots.slice(0,2).map(item=>`<div>${itemChip(item)}<p>${matchupItemReason(item,opponent).map(reason=>`<span>${esc(reason.replace('MR','Magic resist'))}</span>`).join('')||'<span>Best response</span>'}</p></div>`).join('')}</div></article></div></section>`}
summonerSpellPanel=function(c){const setup=summonerSpellRecommendations(c);return `<section class="build-section summoner-panel summoner-compact"><div class="section-head"><h3>Spells</h3><span>${setup.opponent?'matchup':'role'} logic</span></div><div class="summoner-layout"><article class="summoner-primary"><div>${setup.pair.map((name,index)=>summonerSpellCard(name,index?'Second':'Core')).join('')}</div><p>${esc(setup.why.replace('crowd control','control'))}</p></article></div></section>`}
buildSourcePanel=function(c){const champion=slug(c.name),role={Top:'top',Jungle:'jungle',Mid:'mid',AD:'adc',Support:'support'}[c.primaryRole]||'top';return `<section class="build-source build-source-compact"><span>Official item icons + local logic. Check live stats:</span><a href="https://op.gg/ko/lol/champions/${champion}/build?region=kr" target="_blank" rel="noreferrer">OP.GG KR build</a><a href="https://op.gg/ko/lol/champions/${champion}/counters/${role}?region=kr" target="_blank" rel="noreferrer">Counters</a></section>`}
renderBuildsFull=function(){const c=byId(state.focus)||CHAMPIONS[0];if(state.buildOpponent===c.id)state.buildOpponent='';return pageIntro('Builds','Fast item, rune and level-up sheet.')+`<div class="final-library-layout build-library-layout">${libraryList('builds',c.id)}<main class="build-page build-page-compact">${finalChampionHero(c,'builds')}<section class="build-quick-actions"><button type="button" data-picker="focus:focus:0">${portrait(c,'xs')}<span>Champion</span></button><span>${ITEMS.length} items · ${esc(ITEM_DATA.patch||DATA.patch)}</span></section>${matchupBuildPanel(c)}<div class="build-top-grid">${summonerSpellPanel(c)}${runePanel(c)}</div>${buildStyleCards(c)}<div class="build-bottom-grid">${levelUpPanel(c)}${buildSourcePanel(c)}</div></main></div>`}

function buildLanePool(lane){return CHAMPIONS.filter(champion=>settingRoles(champion).includes(lane)||champion.roles.includes(lane))}
function buildLaneOptions(current){return ROLES.map(role=>`<option value="${role}" ${role===current?'selected':''}>${esc(role==='AD'?'Bot / AD':role)}</option>`).join('')}
function buildStyleOptions(current){return [['recommended','Balanced'],['damage','Damage'],['survive','Defensive'],['utility','Utility'],['snowball','Snowball']].map(([id,label])=>`<option value="${id}" ${id===current?'selected':''}>${esc(label)}</option>`).join('')}
function buildOpponentOptions(c,lane,opponent){const pool=buildLanePool(lane).filter(champion=>champion.id!==c.id).sort((a,b)=>a.name.localeCompare(b.name));return `<option value="">Auto / no matchup</option>${pool.map(champion=>`<option value="${champion.id}" ${champion.id===opponent?.id?'selected':''}>${esc(champion.name)} · ${esc(champion.primaryRole)}</option>`).join('')}`}
function buildMatchupControls(c,opponent,lane){return `<section class="build-control-board" aria-label="Build matchup controls"><button type="button" data-picker="focus:focus:0">${portrait(c,'xs')}<span><small>Champion</small><b>${esc(c.name)}</b></span></button><label><span>Lane</span><select data-build-control="buildLane">${buildLaneOptions(lane)}</select></label><label><span>Opponent</span><select data-build-control="buildOpponent">${buildOpponentOptions(c,lane,opponent)}</select></label><label><span>Build style</span><select data-build-control="buildStyle">${buildStyleOptions(state.buildStyle)}</select></label><a href="https://op.gg/ko/lol/champions/${slug(c.name)}/build?region=kr" target="_blank" rel="noreferrer">OP.GG live ↗</a></section>`}
function buildHeroMatchup(c,opponent,lane){const flags=opponent?buildOpponentFlags(opponent):{},threats=opponent?[flags.hybrid?'Mixed damage':flags.magic?'Magic damage':flags.physical?'Physical damage':'Damage',flags.burst?'Burst':null,flags.tank?'Tank/frontline':null,flags.sustain?'Sustain':null,flags.shield?'Shield':null,flags.cc?'Hard CC':null].filter(Boolean):['No matchup selected'];return `<section class="build-matchup-hero"><article class="you">${portrait(c,'md')}<span><small>${esc(lane)} build for</small><b>${esc(c.name)}</b><em>${esc(c.classification?.primary||'Champion')} · ${esc(c.damage?.type||'Damage')}</em></span></article><i>VS</i><article class="enemy">${opponent?portrait(opponent,'md'):'<span class="portrait sm empty">?</span>'}<span><small>${opponent?'Lane opponent':'Optional opponent'}</small><b>${esc(opponent?.name||'Choose matchup')}</b><em>${esc(opponent?[opponent.classification?.primary,opponent.damage?.type].filter(Boolean).join(' · '):'Item adaptation will appear here')}</em></span></article><div class="build-threats">${threats.map(value=>pill(value,semanticTone(value))).join('')}</div></section>`}
function buildCoreRow(label,items,ranked=false){return `<div class="build-plan-row"><b>${esc(label)}</b><p>${items.map((item,index)=>itemChip(item,ranked?index+1:'')).join('')||'<span class="empty">No local item match</span>'}</p></div>`}
function buildPlanPanel(c,opponent){const style=state.buildStyle||'recommended',build=buildRecommendation(c,style),adapt=opponent?matchupBuild(c,opponent):{items:build.situational.slice(0,5),boots:build.boots.slice(0,2)},name={recommended:'Balanced core',damage:'Damage route',survive:'Defensive route',utility:'Utility route',snowball:'Snowball route'}[style]||'Core route';return `<section class="build-section build-plan-panel"><div class="section-head"><h3>${esc(name)}</h3><span>Starter → boots → core → matchup highlight</span></div><div class="build-plan-grid">${buildCoreRow('Start',build.starter)}${buildCoreRow('Boots',opponent?adapt.boots:build.boots.slice(0,2))}${buildCoreRow('Core order',build.core,true)}${buildCoreRow(opponent?'Vs matchup':'Flex items',adapt.items,true)}</div></section>`}
matchupBuildPanel=function(c){const lane=state.buildLane||c.primaryRole||'Top',opponent=byId(state.buildOpponent);return `${buildMatchupControls(c,opponent,lane)}${buildHeroMatchup(c,opponent,lane)}${opponent?`<section class="build-section matchup-answer-panel"><div class="section-head"><h3>Matchup answers</h3><span>Defensive stats, anti-heal/shield, tank answers and boots are highlighted</span></div><div class="matchup-build-grid"><article><small>Priority items</small><div>${matchupBuild(c,opponent).items.map((item,index)=>`<div class="highlight-item">${itemChip(item,index+1)}<p>${matchupItemReason(item,opponent).map(reason=>`<span>${esc(reason.replace('MR','Magic resist'))}</span>`).join('')||'<span>Champion-compatible answer</span>'}</p></div>`).join('')}</div></article><article><small>Boot response</small><div>${matchupBuild(c,opponent).boots.map(item=>`<div class="highlight-item">${itemChip(item)}<p>${matchupItemReason(item,opponent).map(reason=>`<span>${esc(reason.replace('MR','Magic resist'))}</span>`).join('')||'<span>Best local response</span>'}</p></div>`).join('')}</div></article></div></section>`:''}`}
summonerSpellPanel=function(c){const setup=summonerSpellRecommendations(c);return `<section class="build-section summoner-panel summoner-compact"><div class="section-head"><h3>Summoner spells</h3><span>Riot Data Dragon icons · ${setup.opponent?'matchup':'role'} logic</span></div><div class="summoner-layout"><article class="summoner-primary"><header><span>Recommended</span><b>${esc(setup.pair.join(' + '))}</b></header><div>${setup.pair.map((name,index)=>summonerSpellCard(name,index?'Second':'Core')).join('')}</div><p>${esc(setup.why.replace('crowd control','control'))}</p></article></div></section>`}
buildStyleCards=function(c){const styles=[['recommended','Balanced','General core'],['damage','Damage','More carry pressure'],['survive','Defensive','Safer into threat'],['utility','Utility','Actives and setup'],['snowball','Snowball','Lead conversion']];return `<section class="build-section build-styles build-style-selector-panel"><div class="section-head"><h3>Build variants</h3><span>Switch from the style dropdown above</span></div><div class="build-style-grid">${styles.map(([id,label,copy])=>{const active=(state.buildStyle||'recommended')===id,build=buildRecommendation(c,id);return `<button type="button" class="build-style-card ${active?'active':''} style-${id}" data-build-style="${id}" aria-pressed="${active}"><span class="style-head"><span>${termIcon(label)}</span><span><small>${esc(copy)}</small><b>${esc(label)}</b></span></span><span class="build-row core"><b>Core</b><span>${build.core.slice(0,3).map((item,index)=>itemChip(item,index+1)).join('')||'<span class="empty">No item match</span>'}</span></span></button>`}).join('')}</div></section>`}
renderBuildsFull=function(){const c=byId(state.focus)||CHAMPIONS[0];if(state.buildOpponent===c.id)state.buildOpponent='';if(!ROLES.includes(state.buildLane))state.buildLane=c.primaryRole||'Top';const opponent=byId(state.buildOpponent);return pageIntro('Builds','Detailed matchup build sheet: runes, summoner spells, skill max and highlighted counter items.')+`<div class="final-library-layout build-library-layout">${libraryList('builds',c.id)}<main class="build-page build-page-compact">${finalChampionHero(c,'builds')}${matchupBuildPanel(c)}<div class="build-top-grid">${summonerSpellPanel(c)}${runePanel(c)}</div>${buildPlanPanel(c,opponent)}${buildStyleCards(c)}<div class="build-bottom-grid">${levelUpPanel(c)}${buildSourcePanel(c)}</div></main></div>`}

function draftPoolIds(scope){if(scope==='own')return unique([...(state.draftOwnPool||[]),...(state.draftSharedPool||[])]);if(scope==='enemy')return unique([...(state.draftEnemyPool||[]),...(state.draftSharedPool||[])]);if(scope==='shared')return state.draftSharedPool||[];return unique([...(state.draftOwnPool||[]),...(state.draftEnemyPool||[]),...(state.draftSharedPool||[])])}
function parseChampionPoolInput(text=''){const raw=String(text||''),tokens=new Set(raw.toLowerCase().split(/[^a-z0-9]+/).filter(Boolean)),compact=slug(raw),aliases={j4:'jarvaniv',jarvan:'jarvaniv',mundo:'drmundo',drmundo:'drmundo',kog:'kogmaw',kogmaw:'kogmaw',leesin:'leesin',masteryi:'masteryi',mf:'missfortune',nunu:'nunu',reksai:'reksai',tahm:'tahmkench',tf:'twistedfate',wukong:'monkeyking',xin:'xinzhao'};const ids=new Set();CHAMPIONS.forEach(c=>{const keys=unique([c.id,slug(c.name)]);if(keys.some(key=>key.length<=2?tokens.has(key):compact.includes(key)))ids.add(c.id)});tokens.forEach(token=>{const id=aliases[token]||token;if(validChampionId(id))ids.add(id)});return [...ids].filter(validChampionId)}
function importDraftPool(target,text){const ids=parseChampionPoolInput(text);if(!ids.length){notify('Không nhận ra tướng nào trong nội dung nhập');return}const fields=target==='own'?['draftOwnPool']:target==='enemy'?['draftEnemyPool']:target==='shared'?['draftSharedPool']:['draftOwnPool','draftEnemyPool','draftSharedPool'];fields.forEach(field=>{state[field]=unique([...(state[field]||[]),...ids])});state.draftPoolMode=target==='enemy'?'enemy':target==='shared'?'shared':'own';save();render();notify(`Imported ${ids.length} champions to ${target==='shared'?'Both teams':target==='enemy'?'Enemy pool':'Own pool'}`)}
function draftPoolImportPanel(){return `<section class="draft-pool-import"><div class="section-head"><div><h3>Master champion pool input</h3><span>Paste champion names, Riot ID notes, or copied OP.GG Mastery text</span></div><a href="https://www.op.gg/lol/summoners/vn" target="_blank" rel="noreferrer">Open OP.GG ↗</a></div><label><span>Fast input</span><textarea data-pool-import-text rows="5" spellcheck="false" placeholder="VD: Aatrox, Lee Sin, Ahri&#10;Hoặc copy text từ trang OP.GG Mastery rồi paste vào đây"></textarea></label><div class="pool-import-actions"><button type="button" data-action="import-pool" data-pool-target="own">Nạp đội ta</button><button type="button" data-action="import-pool" data-pool-target="enemy">Nạp đội địch</button><button type="button" data-action="import-pool" data-pool-target="shared">Nạp cả hai</button></div><p>Auto 1-click theo Riot ID cần backend proxy giữ Riot API key. Bản static hiện tại dùng cách an toàn: mở OP.GG, copy tab Mastery/champion list, paste vào đây để app tự map sang champion pool.</p></section>`}
function draftPoolCandidates(){const unavailable=new Set([...selectedIds(),...fearlessIds()]),tierValue={'S+':5,S:4,'A+':3,A:2,B:1},mode=state.draftPoolMode;return CHAMPIONS.filter(c=>!unavailable.has(c.id)&&(mode==='all'||mode==='own'&&draftPoolIds('own').includes(c.id)||mode==='enemy'&&draftPoolIds('enemy').includes(c.id)||mode==='shared'&&draftPoolIds('shared').includes(c.id)||mode==='master'&&draftPoolIds('all').includes(c.id)||mode==='meta'&&['S+','S','A+'].includes(c.tier)||mode==='flex'&&c.profiles.flex||mode==='flexLane'&&settingRoles(c).length>1)).sort((a,b)=>{if(state.draftSort==='name')return a.name.localeCompare(b.name);if(state.draftSort==='early')return phaseValue(b.power.early)-phaseValue(a.power.early)||a.name.localeCompare(b.name);if(state.draftSort==='late')return phaseValue(b.power.late)-phaseValue(a.power.late)||a.name.localeCompare(b.name);if(state.draftSort==='mastery')return Number(b.profiles.mastery)-Number(a.profiles.mastery)||a.name.localeCompare(b.name);if(state.draftSort==='flexLane')return settingRoles(b).length-settingRoles(a).length||a.name.localeCompare(b.name);return (tierValue[b.tier]||0)-(tierValue[a.tier]||0)||a.name.localeCompare(b.name)})}
function draftPoolBoard(){const list=draftPoolCandidates(),modes=[['all','All'],['master','Master pool'],['own','Own pool'],['enemy','Enemy pool'],['shared','Both'],['meta','Meta'],['flex','Flex'],['flexLane','Flex lane']],counts=[['Own',state.draftOwnPool.length,'blue'],['Enemy',state.draftEnemyPool.length,'red'],['Both',state.draftSharedPool.length,'shared'],['Master',draftPoolIds('all').length,'master']];return `<section class="draft-pool-board"><div class="section-head"><h3>Champion pool manager</h3><span>${list.length} legal champions · Fearless locks excluded</span></div><div class="pool-summary">${counts.map(([label,count,tone])=>`<span class="${tone}"><small>${label}</small><b>${count}</b></span>`).join('')}<button type="button" data-action="clear-pool" data-pool-target="own">Clear own</button><button type="button" data-action="clear-pool" data-pool-target="enemy">Clear enemy</button><button type="button" data-action="clear-pool" data-pool-target="shared">Clear both</button></div><div class="pool-toolbar"><div class="segmented">${modes.map(([id,label])=>`<button type="button" data-pool-mode="${id}" class="${state.draftPoolMode===id?'active':''}">${label}</button>`).join('')}</div><label>Sort<select data-draft-sort><option value="tier" ${state.draftSort==='tier'?'selected':''}>Tier</option><option value="mastery" ${state.draftSort==='mastery'?'selected':''}>Mastery</option><option value="flexLane" ${state.draftSort==='flexLane'?'selected':''}>Flex lanes</option><option value="name" ${state.draftSort==='name'?'selected':''}>Name</option><option value="early" ${state.draftSort==='early'?'selected':''}>Early</option><option value="late" ${state.draftSort==='late'?'selected':''}>Late</option></select></label></div><div class="pool-grid">${list.slice(0,96).map(c=>`<article>${portrait(c,'sm')}<div><b>${esc(c.name)}</b><small>${esc(settingRoles(c).join(' · ')||c.roles.join(' · '))} · ${esc(c.tier||'—')} · ${esc(c.power.early)}/${esc(c.power.late)}</small></div><button type="button" data-draft-pick="${c.id}">Pick</button><label><input type="checkbox" data-pool-assign="own:${c.id}" ${state.draftOwnPool.includes(c.id)?'checked':''}><span>Own</span></label><label><input type="checkbox" data-pool-assign="enemy:${c.id}" ${state.draftEnemyPool.includes(c.id)?'checked':''}><span>Enemy</span></label><label><input type="checkbox" data-pool-assign="shared:${c.id}" ${state.draftSharedPool.includes(c.id)?'checked':''}><span>Both</span></label></article>`).join('')||'<p class="empty">This pool has no legal champion.</p>'}</div></section>`}
function draftCurrentTurn(){return DRAFT_SEQUENCE[state.draftStep]}
function draftTurnMeta(){const turn=draftCurrentTurn(),done=state.draftStep>=DRAFT_SEQUENCE.length;if(done)return {done,type:'lock',side:'neutral',field:'',index:-1,label:'LOCK GAME',short:'✓'};const [type,field,index]=turn,side=field.startsWith('red')?'red':'blue',role=type==='slot'?ROLES[index]:`BAN ${index+1}`;return {done:false,type,side,field,index,label:`${side.toUpperCase()} ${type==='ban'?'BAN':'PICK'} · ${role}`,short:type==='ban'?'BAN':role}}
function draftRoster(side){const teamLabel=side==='blue'?'TEAM BLUE':'TEAM RED',turn=draftTurnMeta();return `<section class="pro-roster broadcast-roster ${side}"><header><span>${teamLabel}</span><b>${state[side].filter(Boolean).length}/5</b></header><div class="broadcast-picks">${state[side].map((id,index)=>{const c=byId(id),role=ROLES[index],active=turn.type==='slot'&&turn.field===side&&turn.index===index;return `<button type="button" class="broadcast-pick ${c?'filled':'empty'} ${active?'active-turn':''}" data-picker="slot:${side}:${index}" aria-label="${c?`${teamLabel} ${role}: ${c.name}`:`Choose ${teamLabel} ${role}`}">${c?`<img class="draft-splash draft-splash-main" src="${esc(championSplash(c))}" alt="${esc(c.name)}" width="260" height="420" loading="lazy" decoding="async">`:'<span class="draft-pick-empty" aria-hidden="true">+</span>'}<span class="draft-pick-copy"><small>${esc(role)}</small><b>${esc(c?.name||'OPEN')}</b></span>${c?`<i data-clear="${side}:${index}" aria-label="Clear ${esc(c.name)}">×</i>`:''}</button>`}).join('')}</div></section>`}
function draftBanStrip(side){const teamLabel=side==='blue'?'Blue':'Red',field=`${side}Bans`,bans=state[field],turn=draftTurnMeta();return `<section class="draft-ban-panel ${side}"><header><b>${teamLabel}</b></header><div class="draft-ban-slots">${bans.map((id,index)=>{const c=byId(id),active=turn.type==='ban'&&turn.field===field&&turn.index===index;return `<button type="button" class="${c?'filled':''} ${active?'active-turn':''}" data-picker="ban:${field}:${index}" aria-label="${c?`${teamLabel} ban ${index+1}: ${c.name}`:`Choose ${teamLabel} ban ${index+1}`}"><span>${c?portrait(c,'xs'):'+'}</span><b>${esc(c?.name||`B${index+1}`)}</b></button>`}).join('')}</div></section>`}
function draftBanBoard(){return `<section class="draft-top-ban-board" aria-label="Draft bans">${draftBanStrip('blue')}<div class="draft-ban-vs">BANS</div>${draftBanStrip('red')}</section>`}
function draftCenterPanel(){const turn=draftTurnMeta(),locked=fearlessIds().length,done=turn.done;return `<div class="draft-center ${turn.side} ${done?'done':''}" aria-live="polite"><b>${esc(turn.short)}</b><span>${esc(turn.label)}</span><small>${state.draftStep}/${DRAFT_SEQUENCE.length} · ${locked} locked</small><div><button type="button" data-action="draft-prev" ${state.draftStep===0?'disabled':''}>Back</button><button type="button" data-action="draft-next" ${done?'disabled':''}>Skip</button>${done?'<button type="button" class="primary" data-action="complete-game">Lock game</button>':''}</div></div>`}
function fearlessDraftPanel(){const games=state.draftSeries.games.slice(0,4),manual=state.draftSeries.manualLocks||[],locked=fearlessIds();return `<section class="fearless-editor fearless-single"><header><b>Fearless Draft</b><span>${locked.length} locked</span><button type="button" data-picker="fearless:manualLocks:0">+ Lock</button></header><div class="fearless-match-list">${games.map(game=>`<article><strong>Game ${game.number}</strong><div><small>Team 1</small>${(game.blue||[]).filter(Boolean).map(id=>portrait(byId(id)||'','xs')).join('')||'<em>—</em>'}</div><div><small>Team 2</small>${(game.red||[]).filter(Boolean).map(id=>portrait(byId(id)||'','xs')).join('')||'<em>—</em>'}</div></article>`).join('')||'<p class="empty-mini">No game locked</p>'}${manual.length?`<article><strong>Manual</strong><div>${manual.map(id=>{const c=byId(id);return c?`<button type="button" data-fearless-remove="${c.id}">${portrait(c,'xs')}<b>${esc(c.name)}</b><i>×</i></button>`:''}).join('')}</div></article>`:''}</div></section>`}
function draftAssistantDrawer(){const recs=draftRecommendation(),filters=[['meta','Meta'],['mastery','Mastery'],['flex','Flex'],['flexLane','Flex lane'],['carry','Carry']],rules=[['onlyBanPool','Only ban pool'],['onlyOwnPool','Own pool'],['onlyEnemyPool','Enemy pool'],['assistant','Assistant'],['enabled','Enabled']];return `<button type="button" class="draft-assistant-tab" data-action="toggle-draft-assistant" aria-expanded="${state.draftAssistantOpen}">Assistant</button><aside class="draft-assistant drawer ${state.draftAssistantOpen?'open':''}" aria-label="Draft assistant"><div class="section-head"><h3>Assistant</h3><button type="button" data-action="toggle-draft-assistant">×</button></div><div class="draft-drawer-options">${filters.map(([key,label])=>`<label><input type="checkbox" data-draft-filter="${key}" ${state.draftFilters[key]?'checked':''}><span>${esc(label)}</span></label>`).join('')}${rules.map(([key,label])=>`<label><input type="checkbox" data-draft-restriction="${key}" ${state.draftRestrictions[key]?'checked':''}><span>${esc(label)}</span></label>`).join('')}</div><div class="recommend-list">${recs.map(({c,score,reasons})=>`<button type="button" data-draft-pick="${c.id}">${portrait(c,'xs')}<span><b>${esc(c.name)}</b><small>${esc(reasons.join(' · ')||c.roles.join(' · '))}</small></span><em>${score}</em></button>`).join('')||'<p class="empty">No legal champion.</p>'}</div></aside>`}
function draftNeedsBoard(){const sideNeeds=side=>{const metrics=teamMetrics(side),missing=ROLES.filter(role=>!team(side).some(c=>c.roles.includes(role))),needs=[...missing.map(role=>`Missing ${role}`)];if(!metrics.frontline)needs.push('Tank');if(!metrics.engage)needs.push('Engage');if(!metrics.magic)needs.push('AP');if(!metrics.physical)needs.push('AD');return needs};return `<section class="draft-needs-icons"><article class="blue"><b>Blue need</b>${sideNeeds('blue').map(value=>pill(value,'warning')).join('')||pill('Ready','success')}</article><article class="red"><b>Red need</b>${sideNeeds('red').map(value=>pill(value,'warning')).join('')||pill('Ready','success')}</article></section>`}
function renderDraftVision(){return `<div class="draft-match-screen">${draftBanBoard()}<section class="pro-draft-board">${draftRoster('blue')}${draftCenterPanel()}${draftRoster('red')}</section>${fearlessDraftPanel()}${draftNeedsBoard()}</div>`}
function draftWorkbookControls(){return `<section class="draft-workbook-controls compact-pool-tools">${draftPoolImportPanel()}</section>`}
function draftWorkbookContract(){return ''}
function renderDraftFull(){return renderDraftVision()+draftAssistantDrawer()+`<section class="draft-support-deck slim"><div class="draft-support-grid">${draftWorkbookControls()}</div>${draftPoolBoard()}</section>`}
function draftRuleAllows(c){const rules=state.draftRestrictions,turn=DRAFT_SEQUENCE[state.draftStep],type=turn?.[0];if(!rules.enabled||!rules.assistant)return false;if(type==='ban'&&rules.onlyBanPool&&!draftPoolIds('enemy').includes(c.id))return false;if(type==='slot'&&rules.onlyOwnPool&&!draftPoolIds('own').includes(c.id))return false;if(type==='slot'&&rules.onlyEnemyPool&&!draftPoolIds('enemy').includes(c.id))return false;return true}
const draftRecommendationBase=draftRecommendation;
draftRecommendation=function(){return draftRecommendationBase().filter(({c})=>draftRuleAllows(c))};

document.addEventListener('click',event=>{
  if(event.target.closest('select,input,textarea,option'))return;
  const filterSummary=event.target.closest('.picker-filter>summary');if(filterSummary)document.querySelectorAll('.picker-filter[open]').forEach(details=>{if(details!==filterSummary.parentElement)details.removeAttribute('open')});
  const pick=event.target.closest('[data-pick]');if(pick){applyPick(pick.dataset.pick);return}
  const pickerReset=event.target.closest('[data-picker-reset]');if(pickerReset){state.pickerFilters=structuredClone(DEFAULT_STATE.pickerFilters);renderPickerFilters();renderPicker();return}
  const pickerPanel=event.target.closest('[data-picker-filter-panel]');if(pickerPanel){pickerFiltersCollapsed=!pickerFiltersCollapsed;const groups=document.querySelector('.picker-filter-groups');groups?.classList.toggle('collapsed',pickerFiltersCollapsed);pickerPanel.setAttribute('aria-expanded',String(!pickerFiltersCollapsed));pickerPanel.textContent=pickerFiltersCollapsed?teamText('Show filters','Hiện bộ lọc'):teamText('Hide filters','Ẩn bộ lọc');return}
  if(event.target?.id==='champion-picker'){const rect=event.target.getBoundingClientRect(),outside=event.clientX<rect.left||event.clientX>rect.right||event.clientY<rect.top||event.clientY>rect.bottom;if(outside)closePicker();return}
  const language=event.target.closest('[data-lang]');if(language){state.lang=enumValue(language.dataset.lang,['en','vi'],state.lang);save();syncRouteUrl('replaceState');render();return}
  const teamFocusLane=event.target.closest('[data-team-focus-lane]');if(teamFocusLane){state.teamFocusLane=enumValue(teamFocusLane.dataset.teamFocusLane,['Top','Jungle','Mid','Bot'],state.teamFocusLane);save();render();return}
  const teamFocusPhase=event.target.closest('[data-team-focus-phase]');if(teamFocusPhase){state.teamFocusPhase=enumValue(teamFocusPhase.dataset.teamFocusPhase,PHASES,state.teamFocusPhase);save();render();return}
  const checkRole=event.target.closest('button[data-check-role]');if(checkRole){const role=checkRole.dataset.checkRole,roles=finderList('roles'),active=roles.includes(role);state.finder.roles=active?[]:[role];state.checkLane=role;refreshFinderFocus();save();render();return}
  const checkEffectRemove=event.target.closest('[data-check-effect-remove]');if(checkEffectRemove){const value=checkEffectRemove.dataset.checkEffectRemove,values=finderList('skillEffects'),index=values.indexOf(value);if(index>=0)values.splice(index,1);refreshFinderFocus();save();render();return}
  const checkToggle=event.target.closest('label.check-filter-toggle');if(checkToggle){event.preventDefault();const input=checkToggle.querySelector('input[data-filter]');if(!input||input.disabled)return;const values=finderList(input.dataset.filter),index=values.indexOf(input.value);index>=0?values.splice(index,1):values.push(input.value);refreshFinderFocus();save();render();return}
  const route=event.target.closest('button[data-route],a[data-route]');if(route){const routeFocus=event.target.closest('[data-focus]');if(routeFocus)state.focus=routeFocus.dataset.focus;routeTo(route.dataset.route);return}
  const poolImportAction=event.target.closest('[data-action="import-pool"]');if(poolImportAction){const textarea=poolImportAction.closest('.draft-pool-import')?.querySelector('[data-pool-import-text]');importDraftPool(poolImportAction.dataset.poolTarget,textarea?.value||'');return}
  const poolClearAction=event.target.closest('[data-action="clear-pool"]');if(poolClearAction){const target=poolClearAction.dataset.poolTarget,field=target==='enemy'?'draftEnemyPool':target==='shared'?'draftSharedPool':'draftOwnPool';state[field]=[];save();render();notify(`Cleared ${target} pool`);return}
  const assistantToggle=event.target.closest('[data-action="toggle-draft-assistant"]');if(assistantToggle){state.draftAssistantOpen=!state.draftAssistantOpen;save();render();return}
  const action=event.target.closest('[data-action]');if(action){const a=action.dataset.action;if(a==='toggle-nav'){const open=document.body.classList.toggle('nav-open');action.setAttribute('aria-expanded',String(open))}if(a==='toggle-sidebar'){state.sidebarCollapsed=!state.sidebarCollapsed;save();updateShell()}if(a==='close-picker')closePicker();if(a==='recover-view')routeTo('system',{historyMode:'replaceState'});if(a==='reset-workspace'&&confirm('Reset every composition and filter?'))resetState();if(a==='swap-sides')swapSides();if(a==='save-session')saveNamedSession();if(a==='copy-session-link')void copySessionLink();if(a==='export-session')downloadSession();if(a==='toggle-bans'){state.bansVisible=!state.bansVisible;save();render()}if(a==='reset-all-bans'&&confirm('Clear all 10 bans?')){state.blueBans=championSlots([]);state.redBans=championSlots([]);save();render();notify('All bans cleared')}if(a==='reset-side-bans'){const side=action.dataset.side;if(['blue','red'].includes(side)){state[`${side}Bans`]=championSlots([]);save();render();notify(`${side} bans cleared`)}}if(a==='reset-draft'){clearCurrentDraft();save();render()}if(a==='reset-series'&&confirm('Clear the whole series history and Fearless pool?')){clearCurrentDraft();state.draftSeries={...DEFAULT_STATE.draftSeries,games:[]};save();render()}if(a==='draft-prev'){state.draftStep=Math.max(0,state.draftStep-1);save();render()}if(a==='draft-next'){state.draftStep=Math.min(DRAFT_SEQUENCE.length,state.draftStep+1);save();render()}if(a==='auto-roles'){state.blue=assignDraftRoles(state.blue);state.red=assignDraftRoles(state.red);save();render();notify('Optimal roles assigned for both teams')}if(a==='complete-game')completeDraftGame();if(a==='clear-filters'){state.finder=structuredClone(DEFAULT_STATE.finder);save();render()}if(a==='reset-weights'){state.weights={...DEFAULT_STATE.weights};save();render()}return}
  const fearlessRemove=event.target.closest('[data-fearless-remove]');if(fearlessRemove){const id=fearlessRemove.dataset.fearlessRemove,locks=state.draftSeries.manualLocks||[];state.draftSeries.manualLocks=locks.filter(value=>value!==id);save();render();notify('Manual Fearless lock removed');return}
  const clear=event.target.closest('[data-clear]');if(clear){event.stopPropagation();const [field,index]=clear.dataset.clear.split(':');state[field][Number(index)]=null;save();render();return}
  const picker=event.target.closest('[data-picker]');if(picker){openPicker(picker.dataset.picker);return}
  const draftPick=event.target.closest('[data-draft-pick]');if(draftPick){const c=byId(draftPick.dataset.draftPick);if(!c||!draftRuleAllows(c)){notify('Champion is outside the active draft pool rules');return}applyDraftPick(draftPick.dataset.draftPick);return}
  const focus=event.target.closest('[data-focus]');if(focus){state.focus=focus.dataset.focus;save();render();return}
  const library=event.target.closest('[data-library-focus]');if(library){state.focus=library.dataset.libraryFocus;state.route=library.dataset.libraryRoute;save();render();return}
  const draftStep=event.target.closest('[data-draft-step]');if(draftStep){state.draftStep=Number(draftStep.dataset.draftStep);save();render();return}
  const draftMode=event.target.closest('[data-draft-mode]');if(draftMode){state.draftMode=draftMode.dataset.draftMode;save();render();return}
  const analysisMode=event.target.closest('[data-analysis-mode]');if(analysisMode){state.analysisMode=analysisMode.dataset.analysisMode;if(!availableTeamSections().some(([id])=>id===state.teamSection))state.teamSection='overview';save();render();return}
  const perspective=event.target.closest('[data-perspective]');if(perspective){state.perspective=perspective.dataset.perspective;save();render();return}
  const teamSection=event.target.closest('[data-team-section]');if(teamSection){state.teamSection=teamSection.dataset.teamSection;save();render();document.getElementById('app-main').focus();return}
  const mobileTeamSide=event.target.closest('[data-mobile-team-side]');if(mobileTeamSide){state.mobileTeamSide=mobileTeamSide.dataset.mobileTeamSide;save();render();return}
  const historyEntry=event.target.closest('[data-history-index]');if(historyEntry){restoreHistoryEntry(historyEntry.dataset.historyIndex);return}
  const poolMode=event.target.closest('[data-pool-mode]');if(poolMode){state.draftPoolMode=poolMode.dataset.poolMode;save();render();return}
  const seriesFormat=event.target.closest('[data-series-format]');if(seriesFormat){state.draftSeries.format=Number(seriesFormat.dataset.seriesFormat);save();render();return}
  const gameWinner=event.target.closest('[data-game-winner]');if(gameWinner){const [index,winner]=gameWinner.dataset.gameWinner.split(':');state.draftSeries.games[Number(index)].winner=winner;save();render();return}
  const phase=event.target.closest('[data-map-phase]');if(phase){state.mapPhase=phase.dataset.mapPhase;save();render();return}
  const mapLayout=event.target.closest('[data-map-layout]');if(mapLayout){state.mapLayout=mapLayout.dataset.mapLayout;save();render();return}
  const fightPhase=event.target.closest('[data-teamfight-phase]');if(fightPhase){state.teamfightPhase=fightPhase.dataset.teamfightPhase;save();render();return}
  const fightScenario=event.target.closest('[data-fight-scenario]');if(fightScenario){state.fightScenario=fightScenario.dataset.fightScenario;save();render();return}
  const matchupLane=event.target.closest('[data-matchup-lane]');if(matchupLane){state.matchupLane=matchupLane.dataset.matchupLane;save();render();return}
  const matchupOpponent=event.target.closest('[data-matchup-opponent]');if(matchupOpponent){state.matchupOpponent=matchupOpponent.dataset.matchupOpponent;save();render();return}
  const buildStyle=event.target.closest('[data-build-style]');if(buildStyle){state.buildStyle=enumValue(buildStyle.dataset.buildStyle,['recommended','damage','survive','utility','snowball'],state.buildStyle);save();render();return}
  const compareLane=event.target.closest('[data-compare-lane]');if(compareLane){state.compareLane=compareLane.dataset.compareLane;normalizeCompareLineup(state.compareLane);save();render();return}
  const strategyRole=event.target.closest('[data-strategy-role]');if(strategyRole){state.strategyRole=strategyRole.dataset.strategyRole;save();render();return}
  const side=event.target.closest('[data-strategy-side]');if(side){state.strategySide=side.dataset.strategySide;save();render()}
});
document.addEventListener('change',async event=>{
  const myTeam=event.target.closest('[data-my-team-side]');if(myTeam){const side=myTeam.dataset.myTeamSide;state.perspective=myTeam.checked&&['blue','red'].includes(side)?side:'neutral';save();render();return}
  const buildControl=event.target.closest('[data-build-control]');if(buildControl){const field=buildControl.dataset.buildControl;if(field==='buildLane'){state.buildLane=enumValue(buildControl.value,ROLES,state.buildLane);if(state.buildOpponent&&!buildLanePool(state.buildLane).some(champion=>champion.id===state.buildOpponent))state.buildOpponent=''}else if(field==='buildOpponent')state.buildOpponent=validChampionId(buildControl.value)&&buildControl.value!==state.focus?buildControl.value:'';else if(field==='buildStyle')state.buildStyle=enumValue(buildControl.value,['recommended','damage','survive','utility','snowball'],state.buildStyle);save();render();return}
  const buildOpponent=event.target.closest('[data-build-opponent]');if(buildOpponent){state.buildOpponent=validChampionId(buildOpponent.value)&&buildOpponent.value!==state.focus?buildOpponent.value:'';save();render();return}
  const sessionLoad=event.target.closest('[data-session-load]');if(sessionLoad){const record=state.savedSessions.find(item=>item.id===sessionLoad.value);if(record)applySessionPayload(record);return}
  const sessionImport=event.target.closest('[data-session-import]');if(sessionImport){const file=sessionImport.files?.[0];if(!file)return;try{applySessionPayload(JSON.parse(await file.text()));notify('Session JSON imported')}catch(error){console.error('Session import failed.',error);notify(`Import failed · ${error.message}`)}finally{sessionImport.value=''}return}
  const pickerSelect=event.target.closest('[data-picker-filter-select]');if(pickerSelect){const key=pickerSelect.dataset.pickerFilterSelect;state.pickerFilters[key]=pickerSelect.value?[pickerSelect.value]:[];refreshPickerFilterUi(key);renderPicker();return}
  const pickerFilter=event.target.closest('[data-picker-filter]');if(pickerFilter){const key=pickerFilter.dataset.pickerFilter,values=state.pickerFilters[key],index=values.indexOf(pickerFilter.value);if(pickerFilter.checked&&PICKER_SINGLE_FILTERS.has(key))state.pickerFilters[key]=[pickerFilter.value];else pickerFilter.checked&&index<0?values.push(pickerFilter.value):!pickerFilter.checked&&index>=0&&values.splice(index,1);refreshPickerFilterUi(key);renderPicker();return}
  const draftFilter=event.target.closest('[data-draft-filter]');if(draftFilter){state.draftFilters[draftFilter.dataset.draftFilter]=draftFilter.checked;save();render();return}
  const draftRestriction=event.target.closest('[data-draft-restriction]');if(draftRestriction){state.draftRestrictions[draftRestriction.dataset.draftRestriction]=draftRestriction.checked;save();render();return}
  const teamfightFlank=event.target.closest('[data-teamfight-flank]');if(teamfightFlank){state.teamfightFlank=teamfightFlank.checked;save();render();return}
  const poolAssign=event.target.closest('[data-pool-assign]');if(poolAssign){const [type,id]=poolAssign.dataset.poolAssign.split(':'),field=type==='own'?'draftOwnPool':type==='shared'?'draftSharedPool':'draftEnemyPool',index=state[field].indexOf(id);poolAssign.checked&&index<0?state[field].push(id):!poolAssign.checked&&index>=0&&state[field].splice(index,1);save();render();return}
  const draftSort=event.target.closest('[data-draft-sort]');if(draftSort){state.draftSort=draftSort.value;save();render();return}
  const comparePick=event.target.closest('[data-compare-pick]');if(comparePick){const field=comparePick.dataset.comparePick;if(['compareA','compareB','compareBlueSupport','compareRedSupport'].includes(field)){state[field]=comparePick.value;normalizeCompareLineup(state.compareLane);save();render()}return}
  const compareLevel=event.target.closest('[data-compare-level]');if(compareLevel){state.compareLevel=Number(compareLevel.value);save();render();return}
  const fearless=event.target.closest('[data-series-fearless]');if(fearless){state.draftSeries.fearless=fearless.checked;save();render();return}
  const teamfightControl=event.target.closest('[data-teamfight-control]');if(teamfightControl){state[teamfightControl.dataset.teamfightControl]=teamfightControl.value;if(teamfightControl.dataset.teamfightControl==='teamfightMode'){const mode={Aram:'siege',Dragon:'objective',Baron:'objective',Combat:'standard',Basic:'standard'};state.fightScenario=mode[teamfightControl.value]||state.fightScenario}save();render();return}
  const teamfightExecution=event.target.closest('[data-teamfight-execution]');if(teamfightExecution){state[teamfightExecution.dataset.teamfightExecution]=teamfightExecution.value;save();render();return}
  const strategyMacro=event.target.closest('[data-strategy-macro]');if(strategyMacro){state.strategyMacro=strategyMacro.value;save();render();return}
  const checkControl=event.target.closest('[data-check-control]');if(checkControl){const field=checkControl.dataset.checkControl;state[field]=checkControl.value;if(field==='checkLane'&&!byId(state.focus)?.roles.includes(checkControl.value))state.focus=CHAMPIONS.find(c=>c.roles.includes(checkControl.value))?.id||state.focus;save();render();return}
  const checkEffectAdd=event.target.closest('[data-check-effect-add]');if(checkEffectAdd){const value=checkEffectAdd.value,values=finderList('skillEffects');if(value&&!values.includes(value))values.push(value);refreshFinderFocus();save();render();return}
  const checkSelectControl=event.target.closest('[data-check-select]');if(checkSelectControl){state.finder[checkSelectControl.dataset.checkSelect]=checkSelectControl.value?[checkSelectControl.value]:[];refreshFinderFocus();save();render();return}
  const mapRoute=event.target.closest('[data-map-route]');if(mapRoute){state[mapRoute.dataset.mapRoute==='blue'?'mapRouteBlue':'mapRouteRed']=mapRoute.value;save();render();return}
  const routeChampion=event.target.closest('[data-route-champion]');if(routeChampion){state.routeChampion=routeChampion.value;save();render();return}
  const filter=event.target.closest('[data-filter]');if(filter){const values=finderList(filter.dataset.filter),i=values.indexOf(filter.value);filter.checked&&i<0?values.push(filter.value):!filter.checked&&i>=0&&values.splice(i,1);refreshFinderFocus();save();render();return}
  const phase=event.target.closest('[data-phase-filter]');if(phase){state.finder.phase[phase.dataset.phaseFilter]=phase.value;const next=CHAMPIONS.find(champion=>finderPass(champion));if(next)state.focus=next.id;save();render();return}
  const year=event.target.closest('[data-year-filter]');if(year){state.finder.releaseYear=year.value;const next=CHAMPIONS.find(champion=>finderPass(champion));if(next)state.focus=next.id;save();render();return}
  const weight=event.target.closest('[data-weight]');if(weight){state.weights[weight.dataset.weight]=Number(weight.value);save();render()}
});
document.addEventListener('input',event=>{
  if(event.target.matches('[data-session-name]')){state.sessionName=event.target.value.slice(0,80);save();return}
  if(event.target.matches('[data-finder-search]')){const value=event.target.value,pos=value.length;state.finder.search=value;save();clearTimeout(finderSearchTimer);finderSearchTimer=setTimeout(()=>{refreshFinderFocus();render();refocus('[data-finder-search]',pos)},90);return}
  if(event.target.matches('[data-library-search]')){state.libraryQuery=event.target.value;save();render();refocus('[data-library-search]',event.target.value.length)}
  if(event.target.id==='picker-search'){clearTimeout(pickerSearchTimer);pickerSearchTimer=setTimeout(renderPicker,80)}
  if(event.target.matches('[data-weight]')){state.weights[event.target.dataset.weight]=Number(event.target.value);event.target.nextElementSibling.textContent=event.target.value;save()}
});
function refocus(selector,pos){const input=document.querySelector(selector);input?.focus();input?.setSelectionRange(pos,pos)}

// Keep champion selection local to the dialog. Some browsers can lose a
// delegated document click while a modal dialog is in the top layer.
const pickerList=document.getElementById('picker-list');
pickerList?.addEventListener('click',event=>{
  const option=event.target.closest('[data-pick]');
  if(!option||option.disabled)return;
  event.preventDefault();
  event.stopPropagation();
  applyPick(option.dataset.pick);
});
document.querySelector('#champion-picker [data-action="close-picker"]')?.addEventListener('click',event=>{
  event.preventDefault();event.stopImmediatePropagation();closePicker();
});
document.getElementById('champion-picker')?.addEventListener('cancel',event=>{
  event.preventDefault();closePicker();
});
document.addEventListener('keydown',event=>{if(event.key==='Escape'&&document.getElementById('champion-picker')?.open){event.preventDefault();closePicker()}});
document.querySelector('.topbar [data-action="swap-sides"]')?.addEventListener('click',event=>{
  event.preventDefault();event.stopImmediatePropagation();swapSides();
});
window.addEventListener('popstate',()=>{
  const route=new URLSearchParams(location.search).get('route');
  if(!NAVIGATION.some(group=>group.items.some(([id])=>id===route))||route===state.route)return;
  state.route=route;save();render();document.getElementById('app-main').focus();
});

initGlobalHover();syncRouteUrl('replaceState');renderNav();render();
